\n/** 根对象允许 meta、player、openingConfig 等扩展字段（勿与 z.record 做 intersection，避免 MVU 合并失败） */\nexport const Schema = 核心结构;\n","/**\n * MVU ZOD Store\n * 提供响应式的变量访问和修改\n */\nimport { defineMvuDataStore } from '@util/mvu';\nimport { Schema } from './schema';\nimport { normalizeTagMap } from './utils/tagMap';\n/**\n * 主数据存储\n * 使用 defineMvuDataStore 自动与酒馆变量同步\n *\n * 使用 `message_id: -1`（最新一条消息楼层）：同层界面 iframe 常挂在较早楼层（如 0），\n * 而本项目的 MVU 随回合写在当前聊天**最后一条**；若用 `getCurrentMessageId()` 会长期读到空 `角色档案`。\n * 见 `@types/function/variables.d.ts`：负数下标表示从末尾计，`-1` 为最新楼层。\n */\nexport const useDataStore = defineMvuDataStore(Schema, {\n    type: 'message',\n    message_id: -1,\n});\n/**\n * 获取角色列表（响应式）\n */\nexport function useCharacters() {\n    const store = useDataStore();\n    return computed(() => {\n        const chars = store.data.角色档案 || {};\n        return Object.entries(chars).map(([id, char]) => {\n            const name = (char.姓名 && char.姓名 !== '未知' && char.姓名.trim() !== '')\n                ? char.姓名\n                : (char.name || id);\n            const description = char.描写 || char.description || char.desc || '';\n            const status = char.状态 === '出场中' ? 'active' : 'inactive';\n            const currentThought = char.当前内心想法 || char.currentThought || '';\n            const traits = normalizeTagMap(char.性格 ?? char.traits);\n            // 性癖和敏感部位是复杂对象结构（含等级/细节描述等），不走 normalizeTagMap\n            // 它们在下面的 fetishDetails / sensitivePartDetails 中正确解析\n            const hiddenFetish = char.隐藏性癖 || char.hiddenFetish || '';\n            const body = char.身体信息 || {};\n            const stats = char.数值 || {};\n            // 性癖详情（含等级、细节描述、自我合理化）\n            const fetishDetails = {};\n            const rawFetishes = char.性癖 || char.fetishes || {};\n            if (rawFetishes && typeof rawFetishes === 'object') {\n                for (const [key, val] of Object.entries(rawFetishes)) {\n                    if (val && typeof val === 'object') {\n                        fetishDetails[key] = {\n                            level: val.等级 ?? val.level ?? 1,\n                            description: val.细节描述 ?? val.description ?? '',\n                            justification: val.自我合理化 ?? val.justification ?? '',\n                        };\n                    }\n                    else if (typeof val === 'string') {\n                        fetishDetails[key] = {\n                            level: 1,\n                            description: val,\n                            justification: '',\n                        };\n                    }\n                }\n            }\n            // 敏感部位详情（含敏感等级、生理反应、开发细节）\n            const sensitivePartDetails = {};\n            const rawSensitiveParts = char.敏感部位 || char.sensitiveParts || {};\n            if (rawSensitiveParts && typeof rawSensitiveParts === 'object') {\n                for (const [key, val] of Object.entries(rawSensitiveParts)) {\n                    if (val && typeof val === 'object') {\n                        sensitivePartDetails[key] = {\n                            level: val.敏感等级 ?? val.level ?? 1,\n                            reaction: val.生理反应 ?? val.reaction ?? '',\n                            devDetails: val.开发细节 ?? val.devDetails ?? '',\n                        };\n                    }\n                    else if (typeof val === 'string') {\n                        sensitivePartDetails[key] = {\n                            level: 1,\n                            reaction: val,\n                            devDetails: '',\n                        };\n                    }\n                }\n            }\n            // 身份标签\n            const identityTags = char.身份标签 || char.identityTags || {};\n            return {\n                id,\n                name,\n                description,\n                status,\n                basic: {\n                    age: String(body.年龄 || body.age || ''),\n                    height: String(body.身高 || body.height || ''),\n                    weight: String(body.体重 || body.weight || ''),\n                    threeSize: body.三围 || body.threeSize || '',\n                    physique: body.体质特征 || body.physique || '',\n                },\n                stats: {\n                    affection: stats.好感度 || stats.affection || char.affection || 0,\n                    fetish: stats.性癖开发值 || stats.fetish || char.fetish_dev || char.fetish || 0,\n                    lust: stats.发情值 || stats.lust || char.estrus || char.lust || 0,\n                },\n                currentThought,\n                traits,\n                // 性癖和敏感部位：从复杂对象生成可读的字符串格式供UI展示\n                fetishes: Object.fromEntries(Object.entries(fetishDetails).map(([k, v]) => [\n                    k,\n                    v.description || `${k}（等级${v.level}）`,\n                ])),\n                sensitiveParts: Object.fromEntries(Object.entries(sensitivePartDetails).map(([k, v]) => [\n                    k,\n                    v.reaction || `${k}（敏感等级${v.level}）`,\n                ])),\n                hiddenFetish,\n                currentPhysiologicalDesc: char.当前综合生理描述 || char.currentPhysiologicalDesc || '',\n                fetishDetails,\n                sensitivePartDetails,\n                identityTags,\n            };\n        });\n    });\n}\n/**\n * 获取世界规则列表（响应式）\n */\nexport function useWorldRules() {\n    const store = useDataStore();\n    return computed(() => {\n        const rules = store.data.世界规则 || {};\n        const ruleEntries = Object.entries(rules);\n        // 如果有世界规则数据，解析并返回\n        if (ruleEntries.length > 0) {\n            return ruleEntries.map(([title, rule]) => {\n                // 支持中文字段和英文字段回退\n                const displayTitle = rule.名称 || rule.name || title;\n                const desc = rule.效果描述 || rule.desc || rule.description || '';\n                const status = rule.状态 === '生效中' || rule.active === true ? 'active' : 'inactive';\n                const tag = rule.标记 || rule.tag;\n                return {\n                    id: `world-${title}`,\n                    title: displayTitle,\n                    desc,\n                    status,\n                    category: 'world',\n                    tag,\n                };\n            });\n        }\n        // 如果世界规则为空，从 openingConfig.selectedRules 构建\n        const selectedRules = store.data.openingConfig?.selectedRules;\n        if (selectedRules && Array.isArray(selectedRules) && selectedRules.length > 0) {\n            return selectedRules.map((r) => ({\n                id: `world-${r.name}`,\n                title: r.name,\n                desc: r.desc || '',\n                status: 'active',\n                category: 'world',\n            }));\n        }\n        return [];\n    });\n}\n/**\n * 获取区域规则（响应式）\n */\nexport function useRegionalRules() {\n    const store = useDataStore();\n    return computed(() => {\n        const regions = store.data.区域规则 || {};\n        return Object.entries(regions).map(([name, region]) => ({\n            id: `region-${name}`,\n            name: region.名称 || name,\n            description: region.效果描述,\n            status: region.状态 === '生效中' ? 'active' : 'inactive',\n            rules: Object.entries(region.细分规则 || {}).map(([subName, sub]) => ({\n                id: `regional-${name}-${subName}`,\n                title: subName,\n                desc: sub.描述,\n                status: sub.状态 === '生效中' ? 'active' : 'inactive',\n                category: 'regional',\n            })),\n        }));\n    });\n}\n/**\n * 获取个人规则（响应式）\n */\nexport function usePersonalRules() {\n    const store = useDataStore();\n    return computed(() => {\n        const rules = store.data.个人规则 || {};\n        return Object.entries(rules).map(([id, rule]) => ({\n            id: `personal-${id}`,\n            title: rule.名称 || rule.适用对象 || id,\n            desc: rule.效果描述,\n            status: rule.状态 === '生效中' ? 'active' : 'inactive',\n            category: 'personal',\n            target: rule.适用对象,\n            tag: rule.标记,\n        }));\n    });\n}\n/**\n * 按角色分组的个人规则\n */\nexport function usePersonalRulesByCharacter() {\n    const rules = usePersonalRules();\n    return computed(() => {\n        const map = new Map();\n        for (const r of rules.value) {\n            const key = r.target || r.title || '未命名';\n            if (!map.has(key))\n                map.set(key, { active: [], archived: [] });\n            const bucket = map.get(key);\n            if (r.status === 'active')\n                bucket.active.push(r);\n            else\n                bucket.archived.push(r);\n        }\n        return Array.from(map.entries()).map(([groupName, { active, archived }]) => ({\n            groupName,\n            active,\n            archived,\n        }));\n    });\n}\n/**\n * 区域规则中按区域汇总归档规则，用于顶部归档区\n */\nexport function useRegionalArchivedGrouped() {\n    const regions = useRegionalRules();\n    return computed(() => {\n        return regions.value\n            .map((r) => ({\n            regionName: r.name,\n            archived: (r.rules || []).filter((rule) => rule.status !== 'active'),\n        }))\n            .filter((x) => x.archived.length > 0);\n    });\n}\n/**\n * 获取元信息\n */\nexport function useMetaInfo() {\n    const store = useDataStore();\n    return computed(() => store.data.元信息);\n}\n/**\n * 更新元信息中的最近更新时间\n */\nexport function bumpUpdateTime() {\n    const store = useDataStore();\n    store.data.元信息.最近更新时间 = Date.now();\n}\n/**\n * 获取游戏内时间（响应式）\n * 从 MVU 变量中读取，完全由剧情变量控制，非现实时间\n * 使用方式: const gameTime = useGameTime()\n * 在模板中使用: {{ gameTime.年 }}/{{ gameTime.月 }}/{{ gameTime.日 }}\n */\nexport function useGameTime() {\n    const store = useDataStore();\n    return computed(() => ({\n        年: store.data.游戏时间?.年 ?? 2026,\n        月: store.data.游戏时间?.月 ?? 4,\n        日: store.data.游戏时间?.日 ?? 4,\n        时: store.data.游戏时间?.时 ?? 12,\n        分: store.data.游戏时间?.分 ?? 0,\n    }));\n}\n/**\n * 推进游戏内时间（修改变量）\n * 推进指定分钟数，触发 schema 的 transform 处理进位\n */\nexport function advanceGameTime(minutes) {\n    const store = useDataStore();\n    const gameTime = store.data.游戏时间;\n    if (gameTime) {\n        gameTime.分 += Math.round(minutes);\n        console.log(`[Store] 游戏内时间推进 ${minutes} 分钟`, gameTime);\n    }\n}\n/**\n * 设置游戏时间到指定值\n */\nexport function setGameTime(time) {\n    const store = useDataStore();\n    const gameTime = store.data.游戏时间;\n    if (gameTime) {\n        if (time.年 !== undefined)\n            gameTime.年 = time.年;\n        if (time.月 !== undefined)\n            gameTime.月 = time.月;\n        if (time.日 !== undefined)\n            gameTime.日 = time.日;\n        if (time.时 !== undefined)\n            gameTime.时 = time.时;\n        if (time.分 !== undefined)\n            gameTime.分 = time.分;\n        console.log(`[Store] 游戏时间已设置`, gameTime);\n    }\n}\n","function normalizeMessageVariableOption(option) {\n    const o = _.cloneDeep(option);\n    if (o.type === 'message' &&\n        (o.message_id === undefined || o.message_id === 'latest')) {\n        o.message_id = -1;\n    }\n    return o;\n}\n/**\n * @param variable_option 传入对象时与原先行为一致；传入 **函数** 时，在 Pinia store **首次初始化**（首次 `useDataStore()`）时再求值，\n * 用于 `getCurrentMessageId()` 等必须在 iframe 与楼层绑定就绪后才能调用的场景（避免在 `store.ts` 模块顶层求值读到错误楼层）。\n */\nexport function defineMvuDataStore(schema, variable_option, additional_setup) {\n    const isDeferredOption = typeof variable_option === 'function';\n    const storeId = isDeferredOption\n        ? `mvu_data.message.__iframe_current__`\n        : `mvu_data.${_(variable_option)\n            .entries()\n            .sortBy(entry => entry[0])\n            .map(entry => entry[1])\n            .join('.')}`;\n    return defineStore(storeId, errorCatched(() => {\n        const resolvedOption = normalizeMessageVariableOption(isDeferredOption\n            ? variable_option()\n            : variable_option);\n        // 辅助函数：获取 stat_data，统一使用 MVU 格式，检测并修复双重嵌套\n        function getStatData(variables) {\n            if (!variables)\n                return {};\n            // 检查是否是 MVU 格式（有 stat_data 字段）\n            if (variables.stat_data && typeof variables.stat_data === 'object') {\n                // 检测双重嵌套：stat_data 里面还有 stat_data\n                if (variables.stat_data.stat_data && typeof variables.stat_data.stat_data === 'object') {\n                    console.warn('[mvu] 检测到双重嵌套，自动平展');\n                    // 使用内层 stat_data（实际数据）\n                    return variables.stat_data.stat_data;\n                }\n                // 单层 MVU 格式，正常返回 stat_data\n                return variables.stat_data;\n            }\n            // 不是 MVU 格式（可能是空对象或纯数据），返回空对象\n            // 统一要求 MVU 格式\n            return {};\n        }\n        // 辅助函数：设置 stat_data，统一使用 MVU 格式，修复双重嵌套\n        function setStatData(variables, newData) {\n            if (!variables)\n                variables = {};\n            // 检测并修复现有的双重嵌套\n            if (variables.stat_data && typeof variables.stat_data === 'object' &&\n                variables.stat_data.stat_data && typeof variables.stat_data.stat_data === 'object') {\n                console.warn('[mvu] 写入时检测到双重嵌套，自动修复');\n                // 重建正确的单层 MVU 格式\n                const displayData = variables.stat_data.display_data || {};\n                const deltaData = variables.stat_data.delta_data || {};\n                return {\n                    stat_data: newData,\n                    display_data: displayData,\n                    delta_data: deltaData,\n                };\n            }\n            // 统一使用 MVU 格式（单层）\n            // 如果已经有 display_data/delta_data，保留它们\n            const displayData = variables.display_data || {};\n            const deltaData = variables.delta_data || {};\n            return {\n                stat_data: newData,\n                display_data: displayData,\n                delta_data: deltaData,\n            };\n        }\n        const rawVariables = getVariables(resolvedOption);\n        const statData = getStatData(rawVariables);\n        const data = ref(schema.parse(statData, { reportInput: true }));\n        if (additional_setup) {\n            additional_setup(data);\n        }\n        useIntervalFn(() => {\n            const variables = getVariables(resolvedOption);\n            const stat_data = getStatData(variables);\n            const result = schema.safeParse(stat_data);\n            if (result.error) {\n                return;\n            }\n            if (!_.isEqual(data.value, result.data)) {\n                ignoreUpdates(() => {\n                    data.value = result.data;\n                });\n                if (!_.isEqual(stat_data, result.data)) {\n                    updateVariablesWith(variables => setStatData(variables, result.data), resolvedOption);\n                }\n            }\n        }, 2000);\n        const { ignoreUpdates } = watchIgnorable(data, new_data => {\n            const result = schema.safeParse(new_data);\n            if (result.error) {\n                return;\n            }\n            if (!_.isEqual(new_data, result.data)) {\n                ignoreUpdates(() => {\n                    data.value = result.data;\n                });\n            }\n            updateVariablesWith(variables => setStatData(variables, result.data), resolvedOption);\n        }, { deep: true });\n        return { data };\n    }));\n}\n","/**\n * 类型定义文件\n * 定义游戏中使用的所有数据类型\n */\n\n// ==================== 游戏阶段 ====================\n\nexport enum GamePhase {\n  TITLE = 'title',       // 标题界面\n  OPENING = 'opening',   // 开局表单\n  GAME = 'game',         // 游戏主界面\n}\n\n// ==================== 开局表单数据 ====================\n\nexport interface OpeningFormData {\n  playerName: string;           // 玩家名称\n  gameDifficulty: 'easy' | 'normal' | 'hard';  // 游戏难度\n  enableWorldRules: boolean;    // 是否启用世界规则\n  enableRegionalRules: boolean; // 是否启用区域规则\n  enablePersonalRules: boolean; // 是否启用个人规则\n  initialRules: string[];      // 初始规则选择\n  // 新的书本式开局表单字段\n  sceneDescription?: string;   // 场景描述\n  openingSceneDetail?: string; // 开场白场景详细描述（追加到首次生成提示词）\n  selectedRules?: Array<{ name: string; desc: string }>;  // 选中的规则列表\n  characters?: Array<{ name: string; gender: string; desc: string }>;  // 角色列表\n  [key: string]: any;\n}\n\n// ==================== 游戏状态数据 ====================\n\nexport interface GameStatus {\n  phase: 'opening' | 'playing' | 'paused';\n  turn: number;\n  lastUpdated: string;\n  [key: string]: any;\n}\n\nexport interface RuleData {\n  id: string;\n  title: string;\n  desc: string;\n  status: 'active' | 'inactive' | 'pending';\n  category: 'world' | 'regional' | 'personal';\n  createdAt?: string;\n  updatedAt?: string;\n  [key: string]: any;\n}\n\nexport interface CharacterBasic {\n  age?: string;        // 年龄（展示用文案，如 \"17 岁\"）\n  height?: string;     // 身高（如 \"165 cm\"）\n  weight?: string;     // 体重（如 \"48 kg\"）\n  threeSize?: string;  // 三围（如 \"B88 W58 H89\"）\n  physique?: string;   // 体质特征（如 \"敏感型\"）\n  [key: string]: any;\n}\n\nexport interface CharacterData {\n  id: string;\n  name: string;\n  /**\n   * 角色基础身体信息，用于展示与编辑。\n   * 展示头像由 `phoneCharacterAvatarStorage`（本机）管理，与 MVU 角色档案中的头像字段无关。\n   */\n  basic?: CharacterBasic;\n  /**\n   * 数值类属性（与 MVU 角色档案.数值 对应）：\n   * - affection: 好感度（约 -100~100）\n   * - lust: 发情值\n   * - fetish: 性癖开发值\n   */\n  stats?: {\n    [key: string]: number | [number, string];\n  };\n  status: 'active' | 'inactive' | 'dead';\n  description?: string;\n  /** 对应变量「当前综合生理描述」 */\n  currentPhysiologicalDesc?: string;\n  /** 性癖详情（含等级、细节描述、自我合理化） */\n  fetishDetails?: FetishDetails;\n  /** 敏感部位详情（含敏感等级、生理反应、开发细节） */\n  sensitivePartDetails?: SensitivePartDetails;\n  /** 身份标签 */\n  identityTags?: Record<string, string>;\n  [key: string]: any;\n}\n\n/** 性癖详情 */\nexport interface FetishDetails {\n  [fetishName: string]: FetishDetail;\n}\n\nexport interface FetishDetail {\n  /** 等级 */\n  level: number;\n  /** 细节描述 */\n  description: string;\n  /** 自我合理化（傲娇借口） */\n  justification: string;\n}\n\n/** 敏感部位详情 */\nexport interface SensitivePartDetails {\n  [partName: string]: SensitivePartDetail;\n}\n\nexport interface SensitivePartDetail {\n  /** 敏感等级 */\n  level: number;\n  /** 生理反应 */\n  reaction: string;\n  /** 开发细节 */\n  devDetails: string;\n}\n\nexport interface RegionData {\n  id: string;\n  name: string;\n  description?: string;\n  rules: RuleData[];\n  status: 'active' | 'inactive';\n  [key: string]: any;\n}\n\n// 完整的游戏数据结构（用于 MVU 变量存储）\nexport interface GameData {\n  gameStatus: GameStatus;\n  worldRules: RuleData[];\n  regionalRules: RegionData[];\n  personalRules: RuleData[];\n  characters: CharacterData[];\n  player: {\n    name: string;\n    settings: Record<string, any>;\n  };\n  meta: {\n    createdAt: string;\n    updatedAt: string;\n    version: string;\n  };\n}\n\n// ==================== 消息和选项 ====================\n\nexport interface Option {\n  id: string;\n  text: string;\n}\n\nexport interface MessageContent {\n  maintext: string;\n  options: Option[];\n  sum?: string;\n  updateVariable?: string;\n  messageId?: number;\n  userMessageId?: number;\n  fullMessage?: string;\n}\n\n// ==================== 请求类型 ====================\n\nexport type RequestType = 'option' | 'custom' | 'action';\n\nexport interface RequestData {\n  type: RequestType;\n  content: string;\n  optionId?: string;\n  metadata?: Record<string, any>;\n}\n\n// ==================== 请求处理器回调 ====================\n\nexport interface RequestHandlerCallbacks {\n  onDisableOptions?: () => void;\n  onShowGenerating?: () => void;\n  onHideGenerating?: () => void;\n  onEnableOptions?: () => void;\n  onError?: (error: string) => void;\n  onRefreshStory?: () => void;\n  onStreamingUpdate?: (text: string) => void;\n  onRefreshVariables?: () => void;\n  onGenerationComplete?: (result: GameTurnResult) => void;\n}\n\n// ==================== 游戏回合 ====================\n\nexport interface GameTurnResult {\n  generationId: string;\n  maintext: string;\n  options: Option[];\n  sum: string;\n  raw: string;\n  error?: string;\n}\n\nexport interface ValidationResult {\n  valid: boolean;\n  maintext: string;\n  options: Option[];\n  sum: string;\n  error?: string;\n}\n\n// ==================== 编年史 ====================\n\nexport interface ChronicleEntry {\n  messageId: number;\n  turnNumber: number;  // 回合编号 = messageId / 2\n  sum: string;\n  timestamp: string;\n}\n\n// ==================== 变量命令 ====================\n\nexport interface VariableCommand {\n  name: string;\n  value: string | number | boolean;\n  path?: string;\n}\n\n// ==================== MVU 数据格式 ====================\n\nexport interface MvuData {\n  stat_data: Record<string, any>;\n  display_data?: Record<string, any>;\n  delta_data?: Record<string, any>;\n}\n\n// ==================== 世界书条目 ====================\n\nexport interface WorldbookEntry {\n  uid: number;\n  name: string;  // 条目标题（酒馆世界书使用 name 而不是 title）\n  content: string;\n  comment: string;\n  enabled: boolean;  // 是否启用（酒馆使用 enabled 而不是 enable）\n  order: number;\n  position: string;\n  depth: number;\n  selective: boolean;\n  selectiveLogic: string;\n  constant: boolean;\n  key: string[];\n  keysecondary: string[];\n  [key: string]: any;\n}\n\n// ==================== 输出模式配置 ====================\n\nexport type OutputMode = 'single' | 'dual';\n\nexport interface SecondaryApiConfig {\n  url: string;\n  key: string;\n  model: string;\n  /** 失败后的最大重试次数（0–10），总尝试次数 = 1 + 该值 */\n  maxRetries: number;\n  /** 为 true 时运行时从 SillyTavern 当前聊天补全（插头）读取 URL / 密钥 / 模型，不保存密钥到变量 */\n  useTavernMainConnection?: boolean;\n  tasks: {\n    includeVariableUpdate: boolean;\n    includeWorldTrend: boolean;\n    includeResidentLife: boolean;\n  };\n}\n\nexport interface OutputModeSettings {\n  mode: OutputMode;\n  secondaryApi?: SecondaryApiConfig;\n}\n\n// ==================== 导航配置 ====================\n\nexport interface NavItem {\n  id: string;\n  icon: string;\n  label: string;\n}\n\nexport interface PanelConfig {\n  title: string;\n  component: string;\n}\n\n// ==================== 其他设置 ====================\n\nexport type InputActionMode = 'send' | 'append';\n\nexport interface OtherSettings {\n  /** 输入框行为模式：'send' 直接发送，'append' 追加到输入框 */\n  inputActionMode: InputActionMode;\n  /**\n   * 标签验证确认并将 AI 楼层写入后，调用神·数据库 `manualUpdate()`（与插件「立即手动更新」一致）。\n   * 未安装插件时自动跳过，无影响。\n   */\n  enableShujukuManualUpdateAfterConfirm: boolean;\n}\n\nexport const DEFAULT_OTHER_SETTINGS: OtherSettings = {\n  inputActionMode: 'append', // 默认使用追加模式（更安全，不自动发送）\n  enableShujukuManualUpdateAfterConfirm: true,\n};\n","export interface NormalizedOpenAiUrl {\n  /** 用户可配置的“服务基址”，不包含 `/v1` 及更深路径 */\n  base: string;\n  /** 标准 OpenAI 兼容 API 基址：`${base}/v1` */\n  apiBase: string;\n  /** 标准聊天补全 endpoint：`${apiBase}/chat/completions` */\n  chatCompletionsUrl: string;\n  /** 可能的 models endpoint 候选列表（按优先级） */\n  modelsUrlCandidates: string[];\n}\n\nfunction stripTrailingSlashes(s: string): string {\n  return s.replace(/\\/+$/, '');\n}\n\nfunction stripSuffixIgnoreCase(input: string, suffix: string): string {\n  return input.toLowerCase().endsWith(suffix.toLowerCase())\n    ? input.slice(0, input.length - suffix.length)\n    : input;\n}\n\n/**\n * 规范化用户输入的 OpenAI 兼容 API URL。\n *\n * 允许用户输入：\n * - https://host\n * - https://host/v1\n * - https://host/v1/chat/completions\n * - https://host/proxy/v1/chat/completions\n */\nexport function normalizeOpenAiUrl(input: string): NormalizedOpenAiUrl {\n  const raw = (input || '').trim();\n  if (!raw) {\n    throw new Error('API URL 为空');\n  }\n  if (!/^https?:\\/\\//i.test(raw)) {\n    throw new Error('API URL 必须以 http:// 或 https:// 开头');\n  }\n\n  // 用 URL 做基础校验与归一化（保留可能存在的 path 前缀，如 /proxy）\n  const parsed = new URL(raw);\n  const origin = parsed.origin;\n  let path = stripTrailingSlashes(parsed.pathname || '');\n\n  // 去掉常见后缀\n  path = stripSuffixIgnoreCase(path, '/v1/chat/completions');\n  path = stripSuffixIgnoreCase(path, '/chat/completions');\n  path = stripSuffixIgnoreCase(path, '/v1');\n  path = stripTrailingSlashes(path);\n\n  const base = stripTrailingSlashes(`${origin}${path}`);\n  const apiBase = `${base}/v1`;\n\n  return {\n    base,\n    apiBase,\n    chatCompletionsUrl: `${apiBase}/chat/completions`,\n    modelsUrlCandidates: [\n      `${apiBase}/models`, // 标准\n      `${base}/models`, // 部分反代/网关\n    ],\n  };\n}\n\n","/**\n * 从 SillyTavern 当前「聊天补全」连接读取 OpenAI 兼容的 URL / 密钥 / 模型，\n * 供第二 API 与主对话使用相同供应商时使用。\n *\n * 说明：\n * - URL：优先 `chatCompletionSettings.reverse_proxy`，否则 `custom_url`（CUSTOM 源）。\n * - 密钥：优先 `proxy_password`（反代常用），否则尝试在父页面读取各供应商的 #api_key_* 输入框（与酒馆界面同源时可用）。\n * - 模型：`getChatCompletionModel()`。\n * - Azure OpenAI 等路径差异较大，暂不支持，返回 null。\n */\n\n/** 与 SillyTavern openai.js 中各源对应的密钥输入框（按需扩展） */\nconst CHAT_API_KEY_INPUT_SELECTORS = [\n  '#api_key_openai',\n  '#api_key_custom',\n  '#api_key_openrouter',\n  '#api_key_deepseek',\n  '#api_key_moonshot',\n  '#api_key_xai',\n  '#api_key_groq',\n  '#api_key_claude',\n  '#api_key_mistralai',\n  '#api_key_makersuite',\n  '#api_key_azure_openai',\n  '#api_key_siliconflow',\n  '#api_key_cohere',\n  '#api_key_perplexity',\n  '#api_key_ai21',\n  '#api_key_fireworks',\n  '#api_key_cometapi',\n  '#api_key_zai',\n  '#api_key_chutes',\n  '#api_key_electronhub',\n  '#api_key_nanogpt',\n  '#api_key_aimlapi',\n  '#api_key_pollinations',\n  '#api_key_vertexai',\n];\n\nfunction getStGlobals(): { st: any; doc: Document } | null {\n  try {\n    const w = window as unknown as { parent?: Window; SillyTavern?: any };\n    let st: any =\n      typeof SillyTavern !== 'undefined'\n        ? (SillyTavern as any)\n        : w.SillyTavern;\n\n    let doc: Document | null = document;\n\n    if (w.parent && w.parent !== window) {\n      try {\n        const pw = w.parent as unknown as { SillyTavern?: any; document?: Document };\n        if (!st?.chatCompletionSettings && pw.SillyTavern?.chatCompletionSettings) {\n          st = pw.SillyTavern;\n        }\n        if (pw.document) doc = pw.document;\n      } catch {\n        /* 跨域父页面不可访问 */\n      }\n    }\n\n    if (!st?.chatCompletionSettings) return null;\n    return { st, doc: doc || document };\n  } catch {\n    return null;\n  }\n}\n\nfunction readApiKeyFromChatSettingsDom(doc: Document): string {\n  for (const sel of CHAT_API_KEY_INPUT_SELECTORS) {\n    try {\n      const el = doc.querySelector(sel) as HTMLInputElement | null;\n      const v = el?.value?.trim();\n      if (v) return v;\n    } catch {\n      /* ignore */\n    }\n  }\n  return '';\n}\n\nexport type TavernMainOpenAiCredentials = {\n  url: string;\n  key: string;\n  model: string;\n};\n\n/**\n * 读取酒馆当前聊天补全（插头）对应的 OpenAI 兼容 endpoint 与密钥、模型。\n * @returns 失败时 null（例如未连接、Azure、或无法读取密钥）\n */\nexport function getTavernMainOpenAiCredentials(): TavernMainOpenAiCredentials | null {\n  const g = getStGlobals();\n  if (!g) {\n    console.warn('⚠️ [tavernMainConnection] 无法访问 SillyTavern.chatCompletionSettings');\n    return null;\n  }\n\n  const { st, doc } = g;\n  const oai = st.chatCompletionSettings;\n  const src = String(oai?.chat_completion_source ?? '');\n\n  if (/azure/i.test(src)) {\n    console.warn('⚠️ [tavernMainConnection] 当前为 Azure OpenAI，请关闭「使用酒馆相同 API」并手动填写第二 API');\n    return null;\n  }\n\n  let endpoint = String(oai?.reverse_proxy ?? '').trim();\n  if (!endpoint) endpoint = String(oai?.custom_url ?? '').trim();\n  if (!endpoint) {\n    console.warn('⚠️ [tavernMainConnection] 未配置反代地址或自定义 URL');\n    return null;\n  }\n\n  let key = String(oai?.proxy_password ?? '').trim();\n  if (!key) key = readApiKeyFromChatSettingsDom(doc);\n\n  let model = '';\n  try {\n    if (typeof st.getChatCompletionModel === 'function') {\n      model = String(st.getChatCompletionModel() ?? '').trim();\n    }\n  } catch {\n    /* ignore */\n  }\n\n  if (!key) {\n    console.warn(\n      '⚠️ [tavernMainConnection] 未读取到 API 密钥（可尝试在酒馆「代理密码」填写密钥，或改用自定义第二 API）',\n    );\n    return null;\n  }\n\n  return { url: endpoint, key, model };\n}\n\n/**\n * 仅读取反代/自定义 URL 与当前模型名，不读取密钥。\n * 用于「获取模型列表」等可选能力；第二 API 走 `generateRaw` 时不需要密钥。\n */\nexport function getTavernMainOpenAiEndpoint(): { url: string; model: string } | null {\n  const g = getStGlobals();\n  if (!g) return null;\n\n  const { st } = g;\n  const oai = st.chatCompletionSettings;\n  const src = String(oai?.chat_completion_source ?? '');\n\n  if (/azure/i.test(src)) return null;\n\n  let endpoint = String(oai?.reverse_proxy ?? '').trim();\n  if (!endpoint) endpoint = String(oai?.custom_url ?? '').trim();\n  if (!endpoint) return null;\n\n  let model = '';\n  try {\n    if (typeof st.getChatCompletionModel === 'function') {\n      model = String(st.getChatCompletionModel() ?? '').trim();\n    }\n  } catch {\n    /* ignore */\n  }\n\n  return { url: endpoint, model };\n}\n","/**\n * API设置管理工具\n * 管理输出模式设置、世界书条目切换、双API流程处理\n */\n\nimport type { OutputMode, SecondaryApiConfig } from '../types';\nimport type { WorldbookEntry } from '../types';\nimport { normalizeOpenAiUrl } from './openaiUrl';\nimport { loadOutputMode, loadSecondaryApiConfig } from './localSettings';\nimport { getTavernMainOpenAiEndpoint } from './tavernMainConnection';\nimport { DEFAULT_SECONDARY_API_CONFIG } from './secondaryApiDefaults';\n\nexport { DEFAULT_SECONDARY_API_CONFIG };\n\n/** 失败后的最大重试次数（0–10） */\nexport function clampSecondaryApiRetries(n: unknown): number {\n  const x = Math.floor(Number(n));\n  if (Number.isNaN(x)) return 2;\n  return Math.min(10, Math.max(0, x));\n}\n\n// 类型声明\ndeclare function waitGlobalInitialized<T>(global: 'Mvu' | string): Promise<T>;\ndeclare const Mvu: {\n  getMvuData: (options: { type: 'message' | 'chat' | 'character' | 'global'; message_id?: number | 'latest' }) => {\n    stat_data: Record<string, any>;\n    display_data?: Record<string, any>;\n    delta_data?: Record<string, any>;\n  };\n};\n\n// 世界书条目名称常量\nconst WORLDBOOK_ENTRIES = {\n  // 单API模式条目\n  variableUpdateRule: '变量更新规则',\n  variableList: '变量列表',\n  variableOutputFormat: '变量输出格式',\n  singleApiMainFormat: '单API正文格式',\n  // 双API模式条目\n  dualApiMainFormat: '多API正文格式',\n} as const;\n\n/** 变量相关世界书：优先按条目标题前缀识别（与 MVU 脚本命名一致） */\nexport const MVU_WORLDBOOK_ENTRY_PREFIXES = ['[mvu_update]', '[mvu]'] as const;\n\n/**\n * 是否为 MVU 前缀的变量世界书条目（第二 API 优先聚合此类条目）\n */\nexport function isMvUVariableWorldbookEntryName(entryName: string): boolean {\n  const n = String(entryName || '').trim();\n  return MVU_WORLDBOOK_ENTRY_PREFIXES.some((p) => n.startsWith(p));\n}\n\nfunction joinWorldbookEntryBlocks(entries: WorldbookEntry[]): string {\n  return entries\n    .map((e) => `## ${(e.name || '').trim()}\\n${(e.content || '').trim()}`)\n    .filter((block) => block.replace(/^##\\s[^\\n]*\\n/, '').trim().length > 0)\n    .join('\\n\\n---\\n\\n');\n}\n\n/**\n * 从世界书条目解析「变量更新规则 / 变量列表 / 变量输出格式」三段内容。\n * - 若存在任一条目标题以 `[mvu_update]` 或 `[mvu]` 开头：只聚合这些条目（按名称含「输出格式」「变量列表」分流，其余进更新规则）。\n * - 否则回退为按名称子串匹配单条条目（与旧行为兼容）。\n */\nexport function collectVariableWorldbookContentsFromEntries(entries: WorldbookEntry[]): {\n  variableUpdateRule: string;\n  variableList: string;\n  variableOutputFormat: string;\n} {\n  const mvu = entries.filter((e) => isMvUVariableWorldbookEntryName(e.name || ''));\n  if (mvu.length > 0) {\n    const formatEntries: WorldbookEntry[] = [];\n    const listEntries: WorldbookEntry[] = [];\n    const ruleEntries: WorldbookEntry[] = [];\n    for (const e of mvu) {\n      const n = e.name || '';\n      if (n.includes('输出格式')) {\n        formatEntries.push(e);\n      } else if (n.includes('变量列表')) {\n        listEntries.push(e);\n      } else {\n        ruleEntries.push(e);\n      }\n    }\n    return {\n      variableUpdateRule: joinWorldbookEntryBlocks(ruleEntries).trim(),\n      variableList: joinWorldbookEntryBlocks(listEntries).trim(),\n      variableOutputFormat: joinWorldbookEntryBlocks(formatEntries).trim(),\n    };\n  }\n\n  const findByIncludes = (sub: string) => entries.find((e) => (e.name || '').includes(sub));\n  return {\n    variableUpdateRule: (findByIncludes(WORLDBOOK_ENTRIES.variableUpdateRule)?.content || '').trim(),\n    variableList: (findByIncludes(WORLDBOOK_ENTRIES.variableList)?.content || '').trim(),\n    variableOutputFormat: (findByIncludes(WORLDBOOK_ENTRIES.variableOutputFormat)?.content || '').trim(),\n  };\n}\n\n/**\n * 根据输出模式更新世界书条目启用状态\n * @param mode 输出模式\n * @returns 是否成功\n */\nexport async function updateWorldbookEntriesByMode(mode: OutputMode): Promise<boolean> {\n  try {\n    const worldbookName = getCurrentCharWorldbookName();\n    if (!worldbookName) {\n      console.warn('⚠️ [apiSettings] 无法获取当前角色卡绑定的世界书');\n      return false;\n    }\n\n    console.log(`🔄 [apiSettings] 更新世界书条目，模式: ${mode}`);\n\n    // 获取当前世界书条目\n    const entries: WorldbookEntry[] = await getWorldbook(worldbookName);\n\n    if (!entries || entries.length === 0) {\n      console.warn('⚠️ [apiSettings] 世界书条目为空');\n      return false;\n    }\n\n    // 根据模式更新条目启用状态\n    const updatedEntries = entries.map((entry) => {\n      const entryName = entry.name || '';\n\n      if (mode === 'dual') {\n        // 双API模式：关闭单API相关条目，启用双API格式条目\n        // 不自动关闭 [mvu] / [mvu_update] 前缀条目（供 MVU / 第二 API 读取，由用户自行开关）\n        if (\n          !isMvUVariableWorldbookEntryName(entryName) &&\n          (entryName.includes(WORLDBOOK_ENTRIES.variableUpdateRule) ||\n            entryName.includes(WORLDBOOK_ENTRIES.variableList) ||\n            entryName.includes(WORLDBOOK_ENTRIES.variableOutputFormat) ||\n            entryName.includes(WORLDBOOK_ENTRIES.singleApiMainFormat))\n        ) {\n          return { ...entry, enabled: false };\n        }\n        if (entryName.includes(WORLDBOOK_ENTRIES.dualApiMainFormat)) {\n          return { ...entry, enabled: true };\n        }\n      } else {\n        // 单API模式：启用单API相关条目，关闭双API格式条目\n        if (entryName.includes(WORLDBOOK_ENTRIES.variableUpdateRule) ||\n            entryName.includes(WORLDBOOK_ENTRIES.variableList) ||\n            entryName.includes(WORLDBOOK_ENTRIES.variableOutputFormat) ||\n            entryName.includes(WORLDBOOK_ENTRIES.singleApiMainFormat)) {\n          return { ...entry, enabled: true };\n        }\n        if (entryName.includes(WORLDBOOK_ENTRIES.dualApiMainFormat)) {\n          return { ...entry, enabled: false };\n        }\n      }\n\n      return entry;\n    });\n\n    // 应用更新\n    await replaceWorldbook(worldbookName, updatedEntries, { render: 'debounced' });\n\n    console.log(`✅ [apiSettings] 世界书条目更新完成: ${mode} 模式`);\n    return true;\n  } catch (error) {\n    console.error('❌ [apiSettings] 更新世界书条目失败:', error);\n    return false;\n  }\n}\n\n/**\n * 获取当前输出模式（从 localStorage）\n * @returns 输出模式\n */\nexport function getCurrentOutputMode(): OutputMode {\n  try {\n    return loadOutputMode();\n  } catch (error) {\n    console.warn('⚠️ [apiSettings] 获取输出模式失败，默认使用双API模式:', error);\n    return 'dual';\n  }\n}\n\n/**\n * 获取第二API配置（从 localStorage）\n * @returns 第二API配置\n */\nexport function getSecondaryApiConfig(): SecondaryApiConfig {\n  try {\n    return loadSecondaryApiConfig();\n  } catch (error) {\n    console.warn('⚠️ [apiSettings] 获取第二API配置失败:', error);\n    return { ...DEFAULT_SECONDARY_API_CONFIG };\n  }\n}\n\n/**\n * 保存第二API配置\n * @param config 配置对象\n * @returns 是否成功\n */\nexport async function saveSecondaryApiConfig(config: SecondaryApiConfig): Promise<boolean> {\n  try {\n    const { updateStatData } = await import('./dialogAndVariable');\n\n    updateStatData((stat) => {\n      if (!stat.player) {\n        stat.player = { name: '玩家', settings: {} };\n      }\n      if (!stat.player.settings) {\n        stat.player.settings = {};\n      }\n      stat.player.settings.secondaryApi = config;\n      return stat;\n    });\n\n    console.log('✅ [apiSettings] 第二API配置已保存');\n    return true;\n  } catch (error) {\n    console.error('❌ [apiSettings] 保存第二API配置失败:', error);\n    return false;\n  }\n}\n\n/** 第二 API 是否已配置（含「使用酒馆相同连接」） */\nexport function isSecondaryApiConfigured(config: SecondaryApiConfig | null | undefined): boolean {\n  if (!config) return false;\n  if (config.useTavernMainConnection === true) return true;\n  return Boolean(String(config.url || '').trim());\n}\n\nconst SECONDARY_SYSTEM_PROMPT = '你是一个专业的游戏变量更新助手。';\n\n/**\n * 自定义 OpenAI 兼容端点：第二路一律走 `generateRaw` + `custom_api`（短上下文，不附带完整预设/聊天记录）。\n */\nasync function callSecondaryGenerateRawCustom(\n  userPrompt: string,\n  config: SecondaryApiConfig,\n  opts?: { includeSystem?: boolean },\n): Promise<string> {\n  if (typeof generateRaw !== 'function') {\n    throw new Error('generateRaw 不可用');\n  }\n  if (!String(config.key || '').trim()) {\n    throw new Error('第二 API Key 未配置');\n  }\n  const normalized = normalizeOpenAiUrl(config.url);\n  const modelTrim = String(config.model || '').trim();\n  const ordered: { role: 'system' | 'user'; content: string }[] = [];\n  if (opts?.includeSystem !== false) {\n    ordered.push({ role: 'system', content: SECONDARY_SYSTEM_PROMPT });\n  }\n  ordered.push({ role: 'user', content: userPrompt });\n  const genConfig: Parameters<typeof generateRaw>[0] = {\n    user_input: '',\n    should_stream: false,\n    should_silence: true,\n    max_chat_history: 0,\n    ordered_prompts: ordered,\n    custom_api: {\n      apiurl: normalized.base,\n      key: config.key,\n      source: 'openai',\n    },\n  };\n  if (modelTrim) {\n    genConfig.custom_api!.model = modelTrim;\n  }\n  const result = await generateRaw(genConfig);\n  return String(result ?? '');\n}\n\n/**\n * 测试「使用酒馆相同 API」时第二 API 是否可走通（经 `generateRaw`，不读取页面密钥）\n */\nexport async function testSecondaryApiTavernPlug(modelOverride?: string): Promise<void> {\n  if (typeof generateRaw !== 'function') {\n    throw new Error('generateRaw 不可用');\n  }\n  const modelTrim = String(modelOverride || '').trim();\n  const cfg: Parameters<typeof generateRaw>[0] = {\n    user_input: '',\n    should_stream: false,\n    should_silence: true,\n    max_chat_history: 0,\n    ordered_prompts: [{ role: 'user', content: 'Reply with exactly one word: OK' }],\n  };\n  if (modelTrim) {\n    cfg.custom_api = { model: modelTrim };\n  }\n  await generateRaw(cfg);\n}\n\n/**\n * 连接测试：与第二 API 实际调用一致，均走 `generateRaw`（短提示、不注入完整预设/世界书/聊天记录）。\n */\nexport async function testSecondaryApiConnection(config: SecondaryApiConfig): Promise<void> {\n  if (config.useTavernMainConnection) {\n    await testSecondaryApiTavernPlug(config.model);\n    return;\n  }\n  if (!String(config.url || '').trim()) {\n    throw new Error('请填写 API URL');\n  }\n  if (!String(config.key || '').trim()) {\n    throw new Error('请填写 API Key');\n  }\n  await callSecondaryGenerateRawCustom('Reply with exactly one word: OK', config, { includeSystem: false });\n}\n\n/**\n * 从当前配置拉取可用模型列表（OpenAI 兼容 `/v1/models`）。\n */\nexport async function fetchSecondaryApiModelList(config: SecondaryApiConfig): Promise<string[]> {\n  if (typeof getModelList !== 'function') {\n    throw new Error('getModelList 不可用');\n  }\n  if (config.useTavernMainConnection) {\n    const ep = getTavernMainOpenAiEndpoint();\n    if (!ep?.url) {\n      throw new Error('无法读取酒馆当前聊天补全 URL（请检查连接或关闭「使用酒馆相同 API」并手动填写）');\n    }\n    return getModelList({ apiurl: ep.url });\n  }\n  if (!String(config.url || '').trim()) {\n    throw new Error('请填写 API URL');\n  }\n  const normalized = normalizeOpenAiUrl(config.url);\n  return getModelList({ apiurl: normalized.base, key: config.key });\n}\n\n/** 第二 API 即将发起网络请求时派发，供界面显示横幅（`App.vue` 监听） */\nexport const SECONDARY_API_START_EVENT = 'rule-modifier-secondary-api-start' as const;\n\nexport function notifySecondaryApiStart(detail?: { attempt?: number }): void {\n  if (typeof window === 'undefined') return;\n  window.dispatchEvent(new CustomEvent(SECONDARY_API_START_EVENT, { detail: detail ?? {} }));\n}\n\n/**\n * 使用第二API处理变量更新\n * @param maintext 主API生成的正文内容\n * @param config 第二API配置\n * @returns 生成的变量更新内容\n */\nexport async function processWithSecondaryApi(\n  maintext: string,\n  config: SecondaryApiConfig,\n): Promise<string> {\n  const retryCount = clampSecondaryApiRetries(config.maxRetries);\n  const maxAttempts = 1 + retryCount;\n  let lastError: Error | null = null;\n\n  if (!config.useTavernMainConnection && !String(config.url || '').trim()) {\n    throw new Error('第二 API URL 未配置');\n  }\n  if (!config.useTavernMainConnection && !String(config.key || '').trim()) {\n    throw new Error('第二 API Key 未配置');\n  }\n\n  // 获取当前变量数据\n  let currentVariables: Record<string, any> = {};\n  try {\n    await waitGlobalInitialized('Mvu');\n    const mvuData = Mvu.getMvuData({ type: 'message', message_id: 'latest' });\n    currentVariables = mvuData?.stat_data || {};\n    console.log('✅ [apiSettings] 已获取当前变量数据');\n  } catch (error) {\n    console.warn('⚠️ [apiSettings] 获取当前变量数据失败，使用空对象:', error);\n  }\n\n  // 获取世界书内容（变量相关条目）\n  let worldbookContents: {\n    variableUpdateRule: string;\n    variableList: string;\n    variableOutputFormat: string;\n  };\n  try {\n    worldbookContents = await getWorldbookContentsForSecondaryApi();\n    console.log('✅ [apiSettings] 已获取世界书变量相关内容');\n  } catch (error) {\n    console.warn('⚠️ [apiSettings] 获取世界书内容失败，使用默认值:', error);\n    worldbookContents = {\n      variableUpdateRule: '根据正文内容合理更新变量',\n      variableList: '请参考当前变量数据中的字段',\n      variableOutputFormat: `[\n  { \"op\": \"replace\", \"path\": \"/路径\", \"value\": 值 },\n  { \"op\": \"add\", \"path\": \"/路径\", \"value\": 值 }\n]`,\n    };\n  }\n\n  for (let attempt = 0; attempt < maxAttempts; attempt++) {\n    try {\n      console.log(`🔄 [apiSettings] 第二API调用尝试 ${attempt + 1}/${maxAttempts}`);\n\n      // 构建完整提示词（包含变量数据+世界书内容+正文）\n      const prompt = buildSecondaryApiPrompt(\n        maintext,\n        config.tasks,\n        currentVariables,\n        worldbookContents,\n      );\n\n      notifySecondaryApiStart({ attempt: attempt + 1 });\n\n      // 第二路一律 generateRaw：酒馆插头或自定义 URL+密钥+模型\n      const response = config.useTavernMainConnection\n        ? await callSecondaryApiViaGenerateRaw(prompt, config)\n        : await callSecondaryGenerateRawCustom(prompt, config);\n\n      // 解析响应\n      const updateVariable = extractUpdateVariable(response);\n\n      if (updateVariable) {\n        console.log('✅ [apiSettings] 第二API返回有效变量更新');\n        return updateVariable;\n      }\n\n      throw new Error('响应中未找到 <UpdateVariable> 标签');\n    } catch (error) {\n      lastError = error as Error;\n      console.warn(`⚠️ [apiSettings] 第二API调用失败 (尝试 ${attempt + 1}):`, error);\n\n      if (attempt < maxAttempts - 1) {\n        // 等待后重试\n        await new Promise((resolve) => setTimeout(resolve, 1000 * (attempt + 1)));\n      }\n    }\n  }\n\n  // 所有重试都失败了\n  throw new Error(`第二API调用失败（${maxAttempts} 次尝试均失败）: ${lastError?.message}`);\n}\n\n/**\n * 获取世界书内容供第二API使用\n * 读取变量更新规则、变量列表、变量输出格式\n * @returns 世界书条目内容\n */\nasync function getWorldbookContentsForSecondaryApi(): Promise<{\n  variableUpdateRule: string;\n  variableList: string;\n  variableOutputFormat: string;\n}> {\n  const worldbookName = getCurrentCharWorldbookName();\n\n  // 获取世界书条目\n  const entries: WorldbookEntry[] = await getWorldbook(worldbookName);\n\n  if (!entries || entries.length === 0) {\n    throw new Error('世界书条目为空');\n  }\n\n  // 优先聚合 [mvu] / [mvu_update] 前缀条目（即使被禁用也能读取 content）\n  return collectVariableWorldbookContentsFromEntries(entries);\n}\n\n/**\n * 构建第二API提示词\n * @param maintext 主API生成的正文\n * @param tasks 任务配置\n * @param currentVariables 当前变量数据\n * @param worldbookContents 世界书条目内容\n * @returns 完整提示词\n */\nfunction buildSecondaryApiPrompt(\n  maintext: string,\n  tasks: SecondaryApiConfig['tasks'],\n  currentVariables: Record<string, any>,\n  worldbookContents: {\n    variableUpdateRule: string;\n    variableList: string;\n    variableOutputFormat: string;\n  },\n): string {\n  // 构建任务说明\n  let tasksDescription = '';\n  if (tasks.includeVariableUpdate) {\n    tasksDescription += '- 根据正文内容和当前变量数据，按照变量更新规则输出 <UpdateVariable> 标签\\n';\n  }\n  if (tasks.includeWorldTrend) {\n    tasksDescription += '- 分析正文对世界大势的影响，更新相关数据\\n';\n  }\n  if (tasks.includeResidentLife) {\n    tasksDescription += '- 分析正文对居民生活的影响，更新NPC状态\\n';\n  }\n\n  // 准备变量数据JSON（限制大小避免提示词过长）\n  const variablesJson = JSON.stringify(currentVariables, null, 2);\n\n  // 使用世界书中的格式要求，如果没有则使用默认格式\n  const outputFormat = worldbookContents.variableOutputFormat || `[\n  { \"op\": \"replace\", \"path\": \"/路径\", \"value\": 值 },\n  { \"op\": \"add\", \"path\": \"/路径\", \"value\": 值 }\n]`;\n\n  // 分析现有角色的空缺字段\n  const characterArchives = currentVariables?.角色档案 || {};\n  const characterGaps: string[] = [];\n  for (const [charId, charData] of Object.entries(characterArchives)) {\n    const gaps: string[] = [];\n    const c = charData as any;\n    if (!c.性格 || Object.keys(c.性格).length === 0) gaps.push('性格（空对象，需填充）');\n    if (!c.性癖 || Object.keys(c.性癖).length === 0) gaps.push('性癖（空对象，需填充）');\n    if (!c.敏感部位 || Object.keys(c.敏感部位).length === 0) gaps.push('敏感部位（空对象，需填充）');\n    if (!c.隐藏性癖 || c.隐藏性癖 === '') gaps.push('隐藏性癖（空字符串，需填充）');\n    if (!c.当前内心想法 || c.当前内心想法 === '') gaps.push('当前内心想法（空，需基于正文推断）');\n    if (!c.当前综合生理描述 || c.当前综合生理描述 === '') gaps.push('当前综合生理描述（空，需基于正文推断）');\n    if (gaps.length > 0) {\n      characterGaps.push(`- ${c.姓名 || charId}: ${gaps.join('、')}`);\n    }\n  }\n\n  const characterGapSection = characterGaps.length > 0\n    ? `## ⚠️ 现有角色档案空缺检测\\n以下角色存在空缺的字段，请**务必基于正文内容**进行推断和填充：\\n${characterGaps.join('\\n')}\\n\\n`\n    : '';\n\n  return `你是一位专门负责游戏变量更新的AI助手。你的任务是根据提供的游戏正文和当前变量数据，生成变量更新指令。\n\n## 当前变量数据（JSON格式）\n\\`\\`\\`json\n${variablesJson}\n\\`\\`\\`\n\n${worldbookContents.variableList ? `## 变量列表\n${worldbookContents.variableList}\n\n` : ''}${worldbookContents.variableUpdateRule ? `## 变量更新规则\n${worldbookContents.variableUpdateRule}\n\n` : ''}${characterGapSection}## 变量输出格式\n请严格按照以下JSON Patch格式输出变量更新：\n\\`\\`\\`json\n${outputFormat}\n\\`\\`\\`\n\n## 正文内容（请据此分析变量变化）\n<maintext>\n${maintext}\n</maintext>\n\n## 核心任务（优先级从高到低）\n1. **补足现有角色空缺**：检查上述\"现有角色档案空缺检测\"中的角色，基于正文推断并填充所有空缺字段（性格、性癖、敏感部位、隐藏性癖、当前内心想法、当前综合生理描述）\n2. **更新现有角色数值**：根据正文中的互动，更新好感度、发情值、性癖开发值等数值\n3. **创建新角色**：如果正文出现新角色，生成完整的角色档案（不得遗漏任何字段）\n4. **更新世界规则**：如有新规则生效或规则状态变化\n\n## 重要原则\n- **优先使用 replace 操作更新现有角色**，而非 insert 创建新条目\n- **绝对禁止**：让性格、性癖、敏感部位保持为空对象 {}；让隐藏性癖、当前内心想法保持为空白字符串\n- **基于正文推断**：即使没有直接描述，也要根据上下文合理推断角色的心理和生理状态\n\n## 输出要求\n1. 只输出 <UpdateVariable> 标签及其内容\n2. 不要输出正文、解释或任何其他内容\n3. 使用标准的 JSON Patch 格式（op: replace/add/remove）\n4. 确保 JSON 格式正确无误\n5. 检查确认：所有现有角色的空缺字段都已被填充\n\n## 输出示例\n<UpdateVariable>\n[\n  { \"op\": \"replace\", \"path\": \"/元信息/进度\", \"value\": 5 },\n  { \"op\": \"replace\", \"path\": \"/角色档案/角色键/数值/好感度\", \"value\": 10 }\n]\n</UpdateVariable>`;\n}\n\n/**\n * 通过酒馆助手 `generateRaw` 调用当前聊天补全连接（与主对话同一「插头」）\n */\nasync function callSecondaryApiViaGenerateRaw(\n  prompt: string,\n  config: SecondaryApiConfig,\n): Promise<string> {\n  if (typeof generateRaw !== 'function') {\n    throw new Error('generateRaw 不可用，无法使用酒馆相同 API');\n  }\n  const modelTrim = String(config.model || '').trim();\n  const genConfig: Parameters<typeof generateRaw>[0] = {\n    user_input: '',\n    should_stream: false,\n    should_silence: true,\n    max_chat_history: 0,\n    ordered_prompts: [\n      { role: 'system', content: SECONDARY_SYSTEM_PROMPT },\n      { role: 'user', content: prompt },\n    ],\n  };\n  if (modelTrim) {\n    genConfig.custom_api = { model: modelTrim };\n  }\n  const result = await generateRaw(genConfig);\n  return String(result ?? '');\n}\n\n/**\n * 从响应中提取UpdateVariable标签内容\n * @param response API响应\n * @returns UpdateVariable标签内容，或null\n */\nfunction extractUpdateVariable(response: string): string | null {\n  const match = response.match(/<UpdateVariable>([\\s\\S]*?)<\\/UpdateVariable>/i);\n  return match ? match[1].trim() : null;\n}\n\n/**\n * 获取当前角色卡绑定的世界书名称\n * @returns 世界书名称\n */\nfunction getCurrentCharWorldbookName(): string {\n  try {\n    // 从酒馆接口获取当前角色卡的世界书\n    const charInfo = SillyTavern.getCharacterInfo?.();\n    if (charInfo?.worldbook_name) {\n      return charInfo.worldbook_name;\n    }\n\n    // 备选方案：从变量中读取\n    const vars = getVariables({ type: 'character' });\n    if (vars?.worldbook_name) {\n      return vars.worldbook_name;\n    }\n\n    // 默认世界书名称\n    return '规则系统';\n  } catch (error) {\n    console.warn('⚠️ [apiSettings] 获取世界书名称失败，使用默认值:', error);\n    return '规则系统';\n  }\n}\n\n// 导出常量供外部使用\nexport { WORLDBOOK_ENTRIES };\n","/**\n * 编年史更新工具\n * 自动从消息中提取 <sum> 标签内容并更新世界书中的编年史条目\n * 支持回档检测：当玩家回档到较早时期并重roll时，自动替换对应编号的 sum 并清空更高层\n */\n\nimport type { ChronicleEntry, WorldbookEntry } from '../types';\nimport { extractLastSumContent } from './messageParser';\n\n// 编年史条目标题和关键字（用于查找条目）\nconst CHRONICLE_ENTRY_TITLE = '编年史';\nconst CHRONICLE_ENTRY_KEY = 'chronicle';\n\n/**\n * 获取当前角色卡绑定的主要世界书名称\n * 优先使用主要世界书，如果没有则使用第一个附加世界书\n */\nfunction getCurrentCharWorldbookName(): string | null {\n  try {\n    const charWorldbooks = getCharWorldbookNames('current');\n    // 优先使用主要世界书，如果没有则使用第一个附加世界书\n    return charWorldbooks.primary || charWorldbooks.additional[0] || null;\n  } catch (err) {\n    console.error('❌ [chronicleUpdater] 获取角色卡世界书失败:', err);\n    return null;\n  }\n}\n\n/**\n * 从最新消息中提取 <sum> 标签内容\n */\nfunction extractSumFromMessage(messageContent: string): string | null {\n  if (!messageContent) return null;\n\n  const sumText = extractLastSumContent(messageContent);\n  return sumText || null;\n}\n\n/**\n * 格式化时间戳\n */\nfunction formatTimestamp(date: Date = new Date()): string {\n  const year = date.getFullYear();\n  const month = String(date.getMonth() + 1).padStart(2, '0');\n  const day = String(date.getDate()).padStart(2, '0');\n  const hours = String(date.getHours()).padStart(2, '0');\n  const minutes = String(date.getMinutes()).padStart(2, '0');\n\n  return `${year}-${month}-${day} ${hours}:${minutes}`;\n}\n\n/**\n * 计算回合编号\n * 规则：回合编号 = Math.floor(messageId / 2)\n * 因为每个回合包含 user 和 assistant 两条消息\n */\nfunction calculateTurnNumber(messageId: number): number {\n  return Math.floor(messageId / 2);\n}\n\n/**\n * 解析现有的编年史内容\n * 格式：\"# 回合 5 · 楼层 10/11 · 2024-01-01 12:00\\n摘要内容\\n\\n\"\n */\nfunction parseChronicleContent(content: string): ChronicleEntry[] {\n  const entries: ChronicleEntry[] = [];\n\n  if (!content) return entries;\n\n  const lines = content.split('\\n');\n  let currentEntry: Partial<ChronicleEntry> = {};\n\n  for (let i = 0; i < lines.length; i++) {\n    const line = lines[i].trim();\n\n    // 匹配标题行：# 回合 {turnNumber} · 楼层 {messageId}/{messageId+1} · {timestamp}\n    const headerMatch = line.match(/^#\\s*回合\\s*(\\d+)\\s*·\\s*楼层\\s*(\\d+)\\/[\\d]+\\s*·\\s*(.+)$/);\n    if (headerMatch) {\n      // 保存之前的条目\n      if (currentEntry.turnNumber !== undefined && currentEntry.sum) {\n        entries.push(currentEntry as ChronicleEntry);\n      }\n\n      currentEntry = {\n        turnNumber: parseInt(headerMatch[1], 10),\n        messageId: parseInt(headerMatch[2], 10),\n        timestamp: headerMatch[3],\n        sum: '',\n      };\n    } else if (currentEntry.turnNumber !== undefined && line && !line.startsWith('#')) {\n      // 累加摘要内容\n      if (currentEntry.sum) {\n        currentEntry.sum += '\\n' + line;\n      } else {\n        currentEntry.sum = line;\n      }\n    }\n  }\n\n  // 保存最后一个条目\n  if (currentEntry.turnNumber !== undefined && currentEntry.sum) {\n    entries.push(currentEntry as ChronicleEntry);\n  }\n\n  return entries;\n}\n\n/**\n * 格式化编年史条目为世界书内容\n * 按回合编号降序排列（编号大的在前）\n */\nfunction formatChronicleContent(entries: ChronicleEntry[]): string {\n  if (entries.length === 0) return '';\n\n  // 按回合编号排序（降序，最新的回合在前面）\n  const sorted = [...entries].sort((a, b) => b.turnNumber - a.turnNumber);\n\n  return sorted\n    .map(entry => `# 回合 ${entry.turnNumber} · 楼层 ${entry.messageId}/${entry.messageId + 1} · ${entry.timestamp}\\n${entry.sum}`)\n    .join('\\n\\n');\n}\n\n/**\n * 检查并更新编年史\n * 核心逻辑：\n * 1. 计算回合编号 = Math.floor(messageId / 2)\n * 2. 检查该编号是否已存在\n * 3. 如果存在且有更高编号 → 回档重roll：替换当前编号 + 清空所有更高编号\n * 4. 如果不存在 → 正常游玩：添加新条目，保持倒序排列\n */\nexport async function checkAndUpdateChronicle(): Promise<boolean> {\n  try {\n    // 获取最新的 assistant 消息\n    const assistantMessages = getChatMessages(-1, { role: 'assistant' });\n    if (!assistantMessages || assistantMessages.length === 0) {\n      console.log('⚠️ [chronicleUpdater] 没有 assistant 消息可处理');\n      return false;\n    }\n\n    const latestAssistantMessage = assistantMessages[assistantMessages.length - 1];\n    const messageContent = latestAssistantMessage.message || '';\n    const messageId = latestAssistantMessage.message_id;\n\n    // 提取 <sum> 标签内容\n    const sumContent = extractSumFromMessage(messageContent);\n    if (!sumContent) {\n      console.log('⚠️ [chronicleUpdater] 最新消息中没有 <sum> 标签');\n      return false;\n    }\n\n    // 计算回合编号\n    const turnNumber = calculateTurnNumber(messageId);\n\n    console.log(`✅ [chronicleUpdater] 从楼层 ${messageId} 提取到 sum，回合编号: ${turnNumber}`);\n\n    // 获取当前角色卡绑定的世界书\n    const worldbookName = getCurrentCharWorldbookName();\n    if (!worldbookName) {\n      console.error('❌ [chronicleUpdater] 当前角色卡没有绑定世界书');\n      return false;\n    }\n\n    console.log(`📚 [chronicleUpdater] 使用世界书: \"${worldbookName}\"`);\n\n    // 获取世界书条目\n    let worldbookEntries: WorldbookEntry[] = [];\n    try {\n      worldbookEntries = await getWorldbook(worldbookName);\n    } catch (err) {\n      console.warn(`⚠️ [chronicleUpdater] 世界书 \"${worldbookName}\" 不存在，将创建`, err);\n      // 创建新的世界书\n      await createWorldbook(worldbookName, []);\n      worldbookEntries = [];\n    }\n\n    // 查找编年史条目（使用 name 字段，这是酒馆世界书的真实字段名）\n    let chronicleEntry = worldbookEntries.find(\n      entry => entry.name === CHRONICLE_ENTRY_TITLE || entry.key?.includes(CHRONICLE_ENTRY_KEY)\n    );\n\n    // 解析现有的编年史条目\n    let entries: ChronicleEntry[] = [];\n    if (chronicleEntry && chronicleEntry.content) {\n      entries = parseChronicleContent(chronicleEntry.content);\n    }\n\n    // 检查该回合编号是否已存在\n    const existingIndex = entries.findIndex(e => e.turnNumber === turnNumber);\n    // 检查是否有更高回合编号\n    const hasHigherTurnNumber = entries.some(e => e.turnNumber > turnNumber);\n\n    if (existingIndex >= 0 && hasHigherTurnNumber) {\n      // ========== 回档重roll情况 ==========\n      // 1. 替换当前回合编号的 sum\n      entries[existingIndex].sum = sumContent;\n      entries[existingIndex].messageId = messageId;\n      entries[existingIndex].timestamp = formatTimestamp();\n\n      // 2. 清空所有更高回合编号的条目（时间线被重置）\n      const removedCount = entries.filter(e => e.turnNumber > turnNumber).length;\n      entries = entries.filter(e => e.turnNumber <= turnNumber);\n\n      console.log(`🔄 [chronicleUpdater] 检测到回档！回合 ${turnNumber} 被重roll，清空了 ${removedCount} 个更高回合的条目`);\n    } else if (existingIndex >= 0) {\n      // ========== 同一回合更新（非回档）==========\n      // 只是同一个回合的 assistant 消息被更新了（比如编辑消息）\n      entries[existingIndex].sum = sumContent;\n      entries[existingIndex].timestamp = formatTimestamp();\n      console.log(`📝 [chronicleUpdater] 更新回合 ${turnNumber} 的 sum 内容`);\n    } else {\n      // ========== 正常新回合 ==========\n      // 添加新条目\n      const newEntry: ChronicleEntry = {\n        turnNumber,\n        messageId,\n        sum: sumContent,\n        timestamp: formatTimestamp(),\n      };\n      entries.push(newEntry);\n      console.log(`✨ [chronicleUpdater] 新增回合 ${turnNumber} 的编年史条目`);\n    }\n\n    // 限制条目数量（保留最近100回合）\n    if (entries.length > 100) {\n      // 按回合编号排序后保留最新的100个\n      entries = entries\n        .sort((a, b) => b.turnNumber - a.turnNumber)\n        .slice(0, 100);\n    }\n\n    // 格式化新的编年史内容\n    const newContent = formatChronicleContent(entries);\n\n    // 创建或更新编年史条目\n    if (!chronicleEntry) {\n      // 创建新条目（使用酒馆世界书的真实字段名）\n      chronicleEntry = {\n        uid: Date.now(),\n        name: CHRONICLE_ENTRY_TITLE,  // 使用 name 而不是 title\n        content: newContent,\n        comment: '自动生成的游戏编年史，记录每个回合的摘要。支持回档检测：当玩家回档到较早时期并重roll时，会自动替换对应编号的 sum 并清空更高层。',\n        enabled: true,  // 使用 enabled 而不是 enable\n        order: 0,\n        position: 'after_char',\n        depth: 4,\n        selective: false,\n        selectiveLogic: 'and',\n        constant: false,\n        key: [CHRONICLE_ENTRY_KEY, '编年史', '历史', '存档'],\n        keysecondary: [],\n      };\n      worldbookEntries.push(chronicleEntry);\n    } else {\n      // 更新现有条目\n      chronicleEntry.content = newContent;\n      chronicleEntry.comment = chronicleEntry.comment || '自动生成的游戏编年史';\n    }\n\n    // 保存世界书\n    await replaceWorldbook(worldbookName, worldbookEntries, { render: 'debounced' });\n\n    console.log('✅ [chronicleUpdater] 编年史更新成功');\n    return true;\n  } catch (error) {\n    console.error('❌ [chronicleUpdater] 更新编年史失败:', error);\n    return false;\n  }\n}\n\n/**\n * 获取完整的编年史内容\n * 按回合编号倒序返回（最新的回合在前）\n */\nexport async function getChronicle(): Promise<ChronicleEntry[]> {\n  try {\n    const worldbookName = getCurrentCharWorldbookName();\n    if (!worldbookName) {\n      console.error('❌ [chronicleUpdater] 当前角色卡没有绑定世界书');\n      return [];\n    }\n\n    const worldbookEntries = await getWorldbook(worldbookName);\n    const chronicleEntry = worldbookEntries.find(\n      entry => entry.name === CHRONICLE_ENTRY_TITLE || entry.key?.includes(CHRONICLE_ENTRY_KEY)\n    );\n\n    if (!chronicleEntry || !chronicleEntry.content) {\n      return [];\n    }\n\n    const entries = parseChronicleContent(chronicleEntry.content);\n    // 按回合编号降序排序\n    return entries.sort((a, b) => b.turnNumber - a.turnNumber);\n  } catch (error) {\n    console.error('❌ [chronicleUpdater] 获取编年史失败:', error);\n    return [];\n  }\n}\n\n/**\n * 清空编年史\n */\nexport async function clearChronicle(): Promise<boolean> {\n  try {\n    const worldbookName = getCurrentCharWorldbookName();\n    if (!worldbookName) {\n      console.error('❌ [chronicleUpdater] 当前角色卡没有绑定世界书');\n      return false;\n    }\n\n    const worldbookEntries = await getWorldbook(worldbookName);\n    const chronicleEntryIndex = worldbookEntries.findIndex(\n      entry => entry.name === CHRONICLE_ENTRY_TITLE || entry.key?.includes(CHRONICLE_ENTRY_KEY)\n    );\n\n    if (chronicleEntryIndex >= 0) {\n      worldbookEntries[chronicleEntryIndex].content = '';\n      await replaceWorldbook(worldbookName, worldbookEntries, { render: 'debounced' });\n      console.log('✅ [chronicleUpdater] 编年史已清空');\n    }\n\n    return true;\n  } catch (error) {\n    console.error('❌ [chronicleUpdater] 清空编年史失败:', error);\n    return false;\n  }\n}\n\n/**\n * 获取指定回合编号的编年史条目\n */\nexport async function getChronicleByTurnNumber(turnNumber: number): Promise<ChronicleEntry | null> {\n  const entries = await getChronicle();\n  return entries.find(e => e.turnNumber === turnNumber) || null;\n}\n\n/**\n * 删除指定回合编号及之后的所有条目（用于手动回档）\n */\nexport async function deleteFromTurnNumber(turnNumber: number): Promise<boolean> {\n  try {\n    const worldbookName = getCurrentCharWorldbookName();\n    if (!worldbookName) {\n      console.error('❌ [chronicleUpdater] 当前角色卡没有绑定世界书');\n      return false;\n    }\n\n    const worldbookEntries = await getWorldbook(worldbookName);\n    const chronicleEntry = worldbookEntries.find(\n      entry => entry.name === CHRONICLE_ENTRY_TITLE || entry.key?.includes(CHRONICLE_ENTRY_KEY)\n    );\n\n    if (!chronicleEntry || !chronicleEntry.content) {\n      return false;\n    }\n\n    let entries = parseChronicleContent(chronicleEntry.content);\n    // 保留回合编号小于指定编号的条目\n    entries = entries.filter(e => e.turnNumber < turnNumber);\n\n    chronicleEntry.content = formatChronicleContent(entries);\n    await replaceWorldbook(worldbookName, worldbookEntries, { render: 'debounced' });\n\n    console.log(`✅ [chronicleUpdater] 已删除回合 ${turnNumber} 及之后的所有条目`);\n    return true;\n  } catch (error) {\n    console.error('❌ [chronicleUpdater] 删除编年史条目失败:', error);\n    return false;\n  }\n}\n","/**\n * 世界大势和居民生活生成器\n * 在规则变更时调用第二API生成内容\n */\n\nimport type { SecondaryApiConfig } from '../types';\nimport {\n  saveWorldTrendRecord,\n  saveResidentLifeRecord,\n  generateRecordId,\n  type WorldTrendRecord,\n  type ResidentLifeRecord,\n} from './worldLifeStorage';\nimport { getSecondaryApiConfig } from './apiSettings';\n\n// ==================== Type Definitions ====================\n\ninterface WorldTrendPromptResult {\n  affectedScope: string;\n  dailyLifeChanges: string;\n  randomNpcCase: {\n    name: string;\n    identity: string;\n    lifeChange: string;\n    psychological: string;\n  };\n}\n\ninterface ResidentLifePromptResult {\n  otherCharacters: Array<{\n    name: string;\n    status: 'inactive' | 'retired';\n    lifeDescription: string;\n    abnormalChange: string;\n  }>;\n}\n\n// ==================== World Trend Generation ====================\n\n/**\n * 生成世界大势说明\n * @param ruleName 规则名称\n * @param ruleLevel 规则级别（世界或区域）\n * @param ruleDescription 规则效果描述\n * @param affectedRegions 影响的区域列表（可选）\n * @returns 是否成功生成\n */\nexport async function generateWorldTrend(\n  ruleName: string,\n  ruleLevel: 'world' | 'regional',\n  ruleDescription: string,\n  affectedRegions?: string[],\n): Promise<boolean> {\n  const config = getSecondaryApiConfig();\n  if (!config?.tasks?.includeWorldTrend) {\n    console.log('[WorldTrend] 任务未启用，跳过生成');\n    return false;\n  }\n\n  const prompt = buildWorldTrendPrompt(ruleName, ruleLevel, ruleDescription, affectedRegions);\n\n  try {\n    console.log(`[WorldTrend] 开始生成规则「${ruleName}」的世界大势说明...`);\n    const result = await callSecondaryApiForWorldLife(prompt, config);\n    const parsed = parseWorldTrendResult(result);\n\n    if (parsed) {\n      const record: Omit<WorldTrendRecord, 'id'> = {\n        timestamp: Date.now(),\n        triggerRule: ruleName,\n        ruleLevel,\n        affectedScope: parsed.affectedScope,\n        dailyLifeChanges: parsed.dailyLifeChanges,\n        randomNpcCase: parsed.randomNpcCase,\n        isRead: false,\n      };\n      saveWorldTrendRecord({\n        ...record,\n        id: generateRecordId('wt'),\n      });\n      console.log(`[WorldTrend] 已成功保存规则「${ruleName}」的世界大势记录`);\n      return true;\n    }\n  } catch (error) {\n    console.error('[WorldTrend] 生成失败:', error);\n  }\n  return false;\n}\n\n/**\n * 构建世界大势提示词\n */\nfunction buildWorldTrendPrompt(\n  ruleName: string,\n  ruleLevel: 'world' | 'regional',\n  ruleDescription: string,\n  affectedRegions?: string[],\n): string {\n  return `你是一位专门负责描述世界变化对日常生活影响的AI。\n\n## 生效的规则信息\n规则名称：${ruleName}\n规则级别：${ruleLevel === 'world' ? '世界级' : '区域级'}\n规则效果：${ruleDescription}\n${affectedRegions && affectedRegions.length > 0 ? `影响区域：${affectedRegions.join('、')}` : ''}\n\n## 生成任务\n请生成以下内容：\n\n1. **日常生活变化描述** (200-400字)\n   - 描述这个规则生效后，普通人的日常生活发生了哪些变化\n   - 包括工作、社交、出行、消费等方面的变化\n   - 描述应该具体且有画面感\n\n2. **影响范围** (一句话概括)\n   - 这个规则主要影响了哪些地区/人群\n\n3. **随机NPC生活案例**\n   - 随机想象一个NPC（普通人或非主要角色），描述TA在这个变化下的生活\n   - 包括：NPC姓名、身份、具体生活变化、心理反应\n\n## 输出格式\n请严格按照以下JSON格式输出，不要包含任何其他内容：\n\n\\`\\`\\`json\n{\n  \"affectedScope\": \"影响范围描述\",\n  \"dailyLifeChanges\": \"日常生活变化详细描述...\",\n  \"randomNpcCase\": {\n    \"name\": \"NPC姓名\",\n    \"identity\": \"身份/职业\",\n    \"lifeChange\": \"具体生活变化描述...\",\n    \"psychological\": \"心理反应和感受...\"\n  }\n}\n\\`\\`\\`\n\n只输出JSON，不要其他解释。`;\n}\n\n/**\n * 解析世界大势生成结果\n */\nfunction parseWorldTrendResult(content: string): WorldTrendPromptResult | null {\n  try {\n    // Extract JSON from markdown code block if present\n    const jsonMatch = content.match(/```json\\s*([\\s\\S]*?)```/) || content.match(/```\\s*([\\s\\S]*?)```/);\n    const jsonStr = jsonMatch ? jsonMatch[1].trim() : content.trim();\n\n    const data = JSON.parse(jsonStr);\n\n    // Validate structure\n    if (!data.affectedScope || !data.dailyLifeChanges || !data.randomNpcCase) {\n      console.warn('[WorldTrend] 解析结果缺少必要字段:', data);\n      return null;\n    }\n\n    return {\n      affectedScope: String(data.affectedScope),\n      dailyLifeChanges: String(data.dailyLifeChanges),\n      randomNpcCase: {\n        name: String(data.randomNpcCase.name || '未知NPC'),\n        identity: String(data.randomNpcCase.identity || '普通居民'),\n        lifeChange: String(data.randomNpcCase.lifeChange || '暂无变化'),\n        psychological: String(data.randomNpcCase.psychological || '无明显反应'),\n      },\n    };\n  } catch (error) {\n    console.error('[WorldTrend] 解析JSON失败:', error);\n    return null;\n  }\n}\n\n// ==================== Resident Life Generation ====================\n\n/**\n * 生成居民生活说明\n * @param ruleName 规则名称\n * @param targetCharacter 规则目标角色\n * @param ruleDescription 规则效果描述\n * @param inactiveCharacters 未出场角色列表\n * @returns 是否成功生成\n */\nexport async function generateResidentLife(\n  ruleName: string,\n  targetCharacter: string,\n  ruleDescription: string,\n  inactiveCharacters: string[],\n): Promise<boolean> {\n  const config = getSecondaryApiConfig();\n  if (!config?.tasks?.includeResidentLife) {\n    console.log('[ResidentLife] 任务未启用，跳过生成');\n    return false;\n  }\n\n  // Skip if no inactive characters to describe\n  if (inactiveCharacters.length === 0) {\n    console.log('[ResidentLife] 没有未出场角色，跳过生成');\n    return false;\n  }\n\n  const prompt = buildResidentLifePrompt(ruleName, targetCharacter, ruleDescription, inactiveCharacters);\n\n  try {\n    console.log(`[ResidentLife] 开始生成规则「${ruleName}」的居民生活说明...`);\n    const result = await callSecondaryApiForWorldLife(prompt, config);\n    const parsed = parseResidentLifeResult(result);\n\n    if (parsed && parsed.otherCharacters.length > 0) {\n      const record: Omit<ResidentLifeRecord, 'id'> = {\n        timestamp: Date.now(),\n        triggerRule: ruleName,\n        targetCharacter,\n        otherCharacters: parsed.otherCharacters,\n        isRead: false,\n      };\n      saveResidentLifeRecord({\n        ...record,\n        id: generateRecordId('rl'),\n      });\n      console.log(`[ResidentLife] 已成功保存规则「${ruleName}」的居民生活记录`);\n      return true;\n    }\n  } catch (error) {\n    console.error('[ResidentLife] 生成失败:', error);\n  }\n  return false;\n}\n\n/**\n * 构建居民生活提示词\n */\nfunction buildResidentLifePrompt(\n  ruleName: string,\n  targetCharacter: string,\n  ruleDescription: string,\n  inactiveCharacters: string[],\n): string {\n  return `你是一位专门负责描述角色背景生活的AI。\n\n## 生效的规则信息\n规则名称：${ruleName}\n规则目标角色：${targetCharacter}\n规则效果：${ruleDescription}\n\n## 背景角色列表\n以下角色当前未出场或已暂时退场：\n${inactiveCharacters.map((c) => `- ${c}`).join('\\n')}\n\n## 生成任务\n请分析上述个人规则对这些背景角色的影响：\n\n对于每个可能受影响的角色，描述：\n1. 该角色的日常生活变化\n2. 是否有异常或特殊变化（因为个人规则只影响目标角色，其他角色可能觉得奇怪或不理解）\n3. 角色的心理状态\n\n注意：\n- 目标角色是「${targetCharacter}」，个人规则只影响TA\n- 其他角色可能会观察到异常，或者生活间接受到影响\n- 不需要描述所有角色，选择2-4个最相关的角色描述即可\n\n## 输出格式\n请严格按照以下JSON格式输出，不要包含任何其他内容：\n\n\\`\\`\\`json\n{\n  \"otherCharacters\": [\n    {\n      \"name\": \"角色名\",\n      \"status\": \"inactive/retired\",\n      \"lifeDescription\": \"生活变化描述...\",\n      \"abnormalChange\": \"异常变化（如果没有写\\\"无\\\"）...\"\n    }\n  ]\n}\n\\`\\`\\`\n\n只输出JSON，不要其他解释。`;\n}\n\n/**\n * 解析居民生活生成结果\n */\nfunction parseResidentLifeResult(content: string): ResidentLifePromptResult | null {\n  try {\n    // Extract JSON from markdown code block if present\n    const jsonMatch = content.match(/```json\\s*([\\s\\S]*?)```/) || content.match(/```\\s*([\\s\\S]*?)```/);\n    const jsonStr = jsonMatch ? jsonMatch[1].trim() : content.trim();\n\n    const data = JSON.parse(jsonStr);\n\n    // Validate structure\n    if (!Array.isArray(data.otherCharacters)) {\n      console.warn('[ResidentLife] 解析结果缺少otherCharacters数组:', data);\n      return null;\n    }\n\n    const characters = data.otherCharacters\n      .filter((char: any) => char.name && char.lifeDescription)\n      .map((char: any) => ({\n        name: String(char.name),\n        status: (char.status === 'retired' ? 'retired' : 'inactive') as 'inactive' | 'retired',\n        lifeDescription: String(char.lifeDescription),\n        abnormalChange: String(char.abnormalChange || '无'),\n      }));\n\n    return {\n      otherCharacters: characters,\n    };\n  } catch (error) {\n    console.error('[ResidentLife] 解析JSON失败:', error);\n    return null;\n  }\n}\n\n// ==================== API Call Helper ====================\n\nconst WORLD_LIFE_SYSTEM_PROMPT = '你是一个专门描述游戏世界变化的AI助手，擅长分析规则对日常生活的影响。';\n\n/**\n * 调用第二API生成世界/居民生活内容\n * 复用 apiSettings.ts 中的 API 调用逻辑\n */\nasync function callSecondaryApiForWorldLife(\n  prompt: string,\n  config: SecondaryApiConfig,\n): Promise<string> {\n  const modelTrim = String(config.model || '').trim();\n\n  // Check for generateRaw availability\n  if (typeof generateRaw !== 'function') {\n    throw new Error('generateRaw 不可用，无法调用第二API');\n  }\n\n  // Build generation config\n  const genConfig: Parameters<typeof generateRaw>[0] = {\n    user_input: '',\n    should_stream: false,\n    should_silence: true,\n    max_chat_history: 0,\n    ordered_prompts: [\n      { role: 'system', content: WORLD_LIFE_SYSTEM_PROMPT },\n      { role: 'user', content: prompt },\n    ],\n  };\n\n  // Use custom model if specified\n  if (modelTrim) {\n    genConfig.custom_api = { model: modelTrim };\n  }\n\n  // Use custom endpoint if not using tavern main connection\n  if (!config.useTavernMainConnection) {\n    const url = String(config.url || '').trim();\n    const key = String(config.key || '').trim();\n\n    if (!url) {\n      throw new Error('第二 API URL 未配置');\n    }\n    if (!key) {\n      throw new Error('第二 API Key 未配置');\n    }\n\n    genConfig.custom_api = {\n      ...genConfig.custom_api,\n      url: normalizeOpenAiUrl(url),\n      key,\n    };\n  }\n\n  // Call API\n  const result = await generateRaw(genConfig);\n  return String(result ?? '');\n}\n\n/**\n * 规范化OpenAI URL\n */\nfunction normalizeOpenAiUrl(url: string): string {\n  let normalized = url.trim();\n  if (!normalized) return '';\n\n  // Remove trailing slashes\n  normalized = normalized.replace(/\\/+$/, '');\n\n  // Ensure /v1/chat/completions suffix\n  if (!normalized.endsWith('/v1/chat/completions')) {\n    // If it ends with /v1, append /chat/completions\n    if (normalized.endsWith('/v1')) {\n      normalized += '/chat/completions';\n    } else {\n      // Otherwise append full path\n      normalized += '/v1/chat/completions';\n    }\n  }\n\n  return normalized;\n}\n\n/**\n * 执行带重试的API调用\n */\nexport async function callSecondaryApiWithRetry(\n  prompt: string,\n  maxRetries: number = 2,\n): Promise<string> {\n  const config = getSecondaryApiConfig();\n  const maxAttempts = 1 + Math.max(0, Math.min(10, maxRetries));\n  let lastError: Error | null = null;\n\n  for (let attempt = 0; attempt < maxAttempts; attempt++) {\n    try {\n      console.log(`[WorldLife] API调用尝试 ${attempt + 1}/${maxAttempts}`);\n      const result = await callSecondaryApiForWorldLife(prompt, config);\n\n      // Check if result contains valid content\n      if (result && result.trim().length > 0) {\n        return result;\n      }\n\n      throw new Error('API返回空内容');\n    } catch (error) {\n      lastError = error as Error;\n      console.warn(`[WorldLife] API调用失败 (尝试 ${attempt + 1}):`, error);\n\n      if (attempt < maxAttempts - 1) {\n        // Exponential backoff: 1s, 2s, 4s...\n        const delay = 1000 * Math.pow(2, attempt);\n        await new Promise((resolve) => setTimeout(resolve, delay));\n      }\n    }\n  }\n\n  throw new Error(`API调用失败（${maxAttempts} 次尝试均失败）: ${lastError?.message}`);\n}\n","/**\n * 将内容填入对话框并同步修改变量\n * 用于：新增/编辑角色、规则等操作\n * \n * 注意：此版本已适配 ZOD MVU，使用 useDataStore 直接修改变量\n * 修改会自动同步到酒馆变量，无需手动调用 updateVariablesWith\n */\n\nimport type { RuleData, CharacterData, RegionData } from '../types';\nimport { useDataStore, bumpUpdateTime } from '../store';\nimport {\n  parseEditableTextToTagMap,\n  parseEditableTextToFetishRecord,\n  parseEditableTextToSensitiveRecord,\n  type FetishEntryZh,\n  type SensitiveEntryZh,\n} from './tagMap';\nimport { generateWorldTrend, generateResidentLife } from './worldLifeGenerator';\n\n/**\n * 将文本写入前端对话框输入区（不创建新楼层）\n */\nexport async function sendToDialog(message: string): Promise<void> {\n  try {\n    window.dispatchEvent(new CustomEvent('th:copy-to-input', { detail: { message } }));\n    console.log('✅ [dialogAndVariable] 已写入前端对话框输入区:', message.substring(0, 80) + (message.length > 80 ? '...' : ''));\n  } catch (e) {\n    console.warn('⚠️ [dialogAndVariable] 写入前端对话框输入区失败:', e);\n  }\n}\n\n/** 状态转换：active/inactive → 生效中/已归档 */\nfunction enRuleStatusToZh(status: string | undefined, prev: string): string {\n  if (status === 'active') return '生效中';\n  if (status === 'inactive') return '已归档';\n  return prev || '生效中';\n}\n\n/** 解析身体数值 */\nfunction parseBodyNumber(raw: string | undefined, fallback: number): number {\n  if (raw == null || raw === '') return fallback;\n  const n = parseInt(String(raw).replace(/[^\\d-]/g, ''), 10);\n  return Number.isFinite(n) ? n : fallback;\n}\n\n/** 解析标签文本 */\nfunction parseTagLines(text: string): string[] {\n  const raw = String(text ?? '');\n  return raw\n    .split(/\\r?\\n|，|,/g)\n    .map((s) => s.trim())\n    .filter((s) => s.length > 0);\n}\n\n// ---------- 角色 ----------\n\nexport function formatAddCharacterMessage(name: string, description: string): string {\n  const n = name.trim();\n  const d = description.trim();\n  const lines = ['[新增角色]', `姓名：${n}`];\n  if (d) lines.push(`简单描述：${d}`);\n  return lines.join('\\n');\n}\n\nexport function addCharacterToVariables(name: string, description: string): void {\n  const store = useDataStore();\n  const id = `CHR-${Date.now()}`;\n  const n = name.trim() || '未命名';\n  const desc = description.trim();\n\n  store.data.角色档案[id] = {\n    姓名: n,\n    状态: '出场中',\n    描写: desc,\n    当前内心想法: '',\n    性格: {},\n    性癖: {},\n    敏感部位: {},\n    隐藏性癖: '',\n    身体信息: {\n      年龄: 17,\n      身高: 160,\n      体重: 48,\n      三围: '未知',\n      体质特征: '普通',\n    },\n    数值: {\n      好感度: 0,\n      发情值: 0,\n      性癖开发值: 0,\n    },\n    当前综合生理描述: '',\n  };\n  \n  bumpUpdateTime();\n}\n\nexport async function submitAddCharacter(name: string, description: string): Promise<string> {\n  const n = name.trim();\n  if (!n) {\n    toastr.warning('请输入角色名字');\n    return '';\n  }\n  const message = formatAddCharacterMessage(n, description);\n  addCharacterToVariables(n, description);\n  return message;\n}\n\n// ---------- 编辑角色基础信息 ----------\n\nexport function formatEditCharacterBasicMessage(payload: {\n  characterId: string;\n  name?: string;\n  age?: string;\n  height?: string;\n  weight?: string;\n  physique?: string;\n  affection?: number;\n  lust?: number;\n  fetish?: number;\n  [key: string]: any;\n}): string {\n  const lines = ['[编辑角色基础信息]', `角色ID：${payload.characterId}`];\n  if (payload.name != null) lines.push(`姓名：${payload.name}`);\n  if (payload.age != null) lines.push(`年龄：${payload.age}`);\n  if (payload.height != null) lines.push(`身高：${payload.height}`);\n  if (payload.weight != null) lines.push(`体重：${payload.weight}`);\n  if (payload.threeSize != null) lines.push(`三围：${payload.threeSize}`);\n  if (payload.physique != null) lines.push(`体质：${payload.physique}`);\n  if (payload.affection != null) lines.push(`好感度：${payload.affection}`);\n  if (payload.lust != null) lines.push(`发情值：${payload.lust}`);\n  if (payload.fetish != null) lines.push(`性癖开发值：${payload.fetish}`);\n  return lines.join('\\n');\n}\n\nexport function updateCharacterInVariables(characterId: string, updates: Partial<CharacterData>): void {\n  const store = useDataStore();\n  const char = store.data.角色档案[characterId];\n  if (!char) return;\n\n  if (updates.name != null) char.姓名 = updates.name;\n  if (updates.description != null) char.描写 = updates.description;\n\n  if (updates.basic) {\n    const b = updates.basic;\n    if (b.age != null) char.身体信息.年龄 = parseBodyNumber(b.age, char.身体信息.年龄);\n    if (b.height != null) char.身体信息.身高 = parseBodyNumber(b.height, char.身体信息.身高);\n    if (b.weight != null) char.身体信息.体重 = parseBodyNumber(b.weight, char.身体信息.体重);\n    if (b.threeSize != null) char.身体信息.三围 = String(b.threeSize);\n    if (b.physique != null) char.身体信息.体质特征 = String(b.physique);\n  }\n\n  if (updates.stats) {\n    if (typeof updates.stats.affection === 'number') char.数值.好感度 = updates.stats.affection;\n    if (typeof updates.stats.lust === 'number') char.数值.发情值 = updates.stats.lust;\n    if (typeof updates.stats.fetish === 'number') char.数值.性癖开发值 = updates.stats.fetish;\n  }\n\n  bumpUpdateTime();\n}\n\nexport async function submitEditCharacterBasic(\n  characterId: string,\n  payload: Record<string, string | number | undefined>,\n): Promise<string> {\n  const message = formatEditCharacterBasicMessage({ characterId, ...payload });\n\n  const stats: Record<string, number> = {};\n  if (typeof payload.affection === 'number') stats.affection = payload.affection;\n  if (typeof payload.lust === 'number') stats.lust = payload.lust;\n  if (typeof payload.fetish === 'number') stats.fetish = payload.fetish;\n\n  const basic: CharacterData['basic'] = {\n    age: payload.age as string | undefined,\n    height: payload.height as string | undefined,\n    weight: payload.weight as string | undefined,\n    threeSize: payload.threeSize as string | undefined,\n    physique: payload.physique as string | undefined,\n  };\n\n  updateCharacterInVariables(\n    characterId,\n    {\n      name: (payload.name as string | undefined) ?? undefined,\n      basic,\n      stats: Object.keys(stats).length ? (stats as Record<string, number>) : undefined,\n    } as Partial<CharacterData>,\n  );\n  return message;\n}\n\n/** 编辑角色头像：独立子系统，仅写浏览器 localStorage + 父窗口转发；不读、不写 MVU 中的头像字段；不生成对话框文案 */\nexport async function submitEditCharacterAvatar(\n  characterId: string,\n  avatarUrl: string,\n  displayName?: string | null,\n): Promise<string> {\n  const { setCharacterAvatarOverride } = await import('../../shared/phoneCharacterAvatarStorage');\n  const u = String(avatarUrl ?? '').trim();\n  const dn = String(displayName ?? '').trim();\n  setCharacterAvatarOverride(characterId, u, dn ? { displayName: dn } : undefined);\n  try {\n    // eslint-disable-next-line @typescript-eslint/no-explicit-any\n    const t = (globalThis as any).toastr;\n    if (t?.success) {\n      t.success(!u ? '已清除本机头像覆盖' : '头像已保存（本机并与小手机同步）');\n    }\n  } catch {\n    /* */\n  }\n  return '';\n}\n\n// ---------- 编辑角色心理/性癖/敏感部位 ----------\n\nfunction formatTagMapLine(label: string, rec: Record<string, string> | undefined): string | null {\n  if (rec == null || Object.keys(rec).length === 0) return null;\n  const s = Object.entries(rec)\n    .map(([k, v]) => (String(v).trim() ? `${k}：${v}` : k))\n    .join('、');\n  return `${label}：${s}`;\n}\n\nfunction formatFetishPsychLine(rec: Record<string, FetishEntryZh> | undefined): string | null {\n  if (rec == null || Object.keys(rec).length === 0) return null;\n  const s = Object.entries(rec)\n    .map(([k, o]) => {\n      const d = o.细节描述.trim();\n      return d ? `${k}：Lv.${o.等级} ${d}` : `${k}：Lv.${o.等级}`;\n    })\n    .join('、');\n  return `性癖：${s}`;\n}\n\nfunction formatSensitivePsychLine(rec: Record<string, SensitiveEntryZh> | undefined): string | null {\n  if (rec == null || Object.keys(rec).length === 0) return null;\n  const s = Object.entries(rec)\n    .map(([k, o]) => {\n      const r = o.生理反应.trim();\n      return r ? `${k}：Lv.${o.敏感等级} ${r}` : `${k}：Lv.${o.敏感等级}`;\n    })\n    .join('、');\n  return `敏感部位：${s}`;\n}\n\nexport function formatEditCharacterPsychMessage(payload: {\n  characterId: string;\n  当前内心想法?: string;\n  性格?: Record<string, string>;\n  性癖?: Record<string, FetishEntryZh>;\n  敏感部位?: Record<string, SensitiveEntryZh>;\n  隐藏性癖?: string;\n}): string {\n  const lines = ['[编辑角色心理与性癖]', `角色ID：${payload.characterId}`];\n  if (payload.当前内心想法 != null) lines.push(`当前内心想法：${String(payload.当前内心想法)}`);\n  const t1 = formatTagMapLine('性格', payload.性格);\n  if (t1) lines.push(t1);\n  const t2 = formatFetishPsychLine(payload.性癖);\n  if (t2) lines.push(t2);\n  const t3 = formatSensitivePsychLine(payload.敏感部位);\n  if (t3) lines.push(t3);\n  if (payload.隐藏性癖 != null) lines.push(`隐藏性癖：${String(payload.隐藏性癖)}`);\n  return lines.join('\\n');\n}\n\nexport function updateCharacterPsychInChineseVariables(\n  characterId: string,\n  updates: {\n    当前内心想法?: string;\n    性格?: Record<string, string>;\n    性癖?: Record<string, FetishEntryZh>;\n    敏感部位?: Record<string, SensitiveEntryZh>;\n    隐藏性癖?: string;\n  },\n): void {\n  const store = useDataStore();\n  const char = store.data.角色档案[characterId];\n  if (!char) return;\n\n  if (updates.当前内心想法 != null) char.当前内心想法 = updates.当前内心想法;\n  if (updates.性格 != null) char.性格 = updates.性格;\n  if (updates.性癖 != null) char.性癖 = updates.性癖;\n  if (updates.敏感部位 != null) char.敏感部位 = updates.敏感部位;\n  if (updates.隐藏性癖 != null) char.隐藏性癖 = updates.隐藏性癖;\n\n  bumpUpdateTime();\n}\n\nexport async function submitEditCharacterPsych(\n  characterId: string,\n  payload: {\n    thought?: string;\n    traitsText?: string;\n    fetishesText?: string;\n    sensitivePartsText?: string;\n    hiddenFetish?: string;\n  },\n): Promise<string> {\n  const updates: {\n    当前内心想法?: string;\n    性格?: Record<string, string>;\n    性癖?: Record<string, FetishEntryZh>;\n    敏感部位?: Record<string, SensitiveEntryZh>;\n    隐藏性癖?: string;\n  } = {};\n\n  if (payload.thought !== undefined) updates.当前内心想法 = String(payload.thought ?? '');\n  if (payload.traitsText !== undefined) updates.性格 = parseEditableTextToTagMap(payload.traitsText ?? '');\n  if (payload.fetishesText !== undefined) updates.性癖 = parseEditableTextToFetishRecord(payload.fetishesText ?? '');\n  if (payload.sensitivePartsText !== undefined) {\n    updates.敏感部位 = parseEditableTextToSensitiveRecord(payload.sensitivePartsText ?? '');\n  }\n  if (payload.hiddenFetish !== undefined) updates.隐藏性癖 = String(payload.hiddenFetish ?? '');\n\n  const message = formatEditCharacterPsychMessage({ characterId, ...updates });\n  updateCharacterPsychInChineseVariables(characterId, updates);\n  return message;\n}\n\n// ---------- 编辑角色性癖详情 ----------\n\nexport interface FetishDetailUpdate {\n  /** 性癖名称 */\n  name: string;\n  /** 等级（1-10） */\n  level?: number;\n  /** 细节描述 */\n  description?: string;\n  /** 自我合理化 */\n  justification?: string;\n}\n\nexport interface SensitivePartDetailUpdate {\n  /** 部位名称 */\n  name: string;\n  /** 敏感等级（1-10） */\n  level?: number;\n  /** 生理反应 */\n  reaction?: string;\n  /** 开发细节 */\n  devDetails?: string;\n}\n\n/**\n * 更新角色的性癖详情\n */\nexport function updateCharacterFetishDetails(\n  characterId: string,\n  updates: FetishDetailUpdate[],\n): void {\n  const store = useDataStore();\n  const char = store.data.角色档案[characterId];\n  if (!char) return;\n\n  // 确保性癖对象存在\n  if (!char.性癖) char.性癖 = {};\n  if (!char.性癖) char.性癖 = {};\n\n  for (const update of updates) {\n    const existing = char.性癖[update.name];\n    char.性癖[update.name] = {\n      等级: update.level ?? (existing?.等级 ?? existing?.level ?? 1),\n      细节描述: update.description ?? (existing?.细节描述 ?? existing?.description ?? ''),\n      自我合理化: update.justification ?? (existing?.自我合理化 ?? existing?.justification ?? ''),\n    };\n  }\n\n  bumpUpdateTime();\n}\n\n/**\n * 更新角色的敏感部位详情\n */\nexport function updateCharacterSensitivePartDetails(\n  characterId: string,\n  updates: SensitivePartDetailUpdate[],\n): void {\n  const store = useDataStore();\n  const char = store.data.角色档案[characterId];\n  if (!char) return;\n\n  // 确保敏感部位对象存在\n  if (!char.敏感部位) char.敏感部位 = {};\n\n  for (const update of updates) {\n    const existing = char.敏感部位[update.name];\n    char.敏感部位[update.name] = {\n      敏感等级: update.level ?? (existing?.敏感等级 ?? existing?.level ?? 1),\n      生理反应: update.reaction ?? (existing?.生理反应 ?? existing?.reaction ?? ''),\n      开发细节: update.devDetails ?? (existing?.开发细节 ?? existing?.devDetails ?? ''),\n    };\n  }\n\n  bumpUpdateTime();\n}\n\n/**\n * 更新角色的身份标签\n */\nexport function updateCharacterIdentityTags(\n  characterId: string,\n  tags: Record<string, string>,\n): void {\n  const store = useDataStore();\n  const char = store.data.角色档案[characterId];\n  if (!char) return;\n\n  char.身份标签 = { ...tags };\n\n  bumpUpdateTime();\n}\n\n/**\n * 格式化性癖详情更新消息\n */\nexport function formatFetishDetailMessage(characterId: string, updates: FetishDetailUpdate[]): string {\n  const lines = ['[编辑性癖详情]', `角色ID：${characterId}`];\n  for (const u of updates) {\n    const parts = [u.name];\n    if (u.level != null) parts.push(`等级${u.level}`);\n    if (u.description) parts.push(`「${u.description}」`);\n    if (u.justification) parts.push(`（自我合理化：${u.justification}）`);\n    lines.push(`- ${parts.join('：')}`);\n  }\n  return lines.join('\\n');\n}\n\n/**\n * 格式化敏感部位详情更新消息\n */\nexport function formatSensitivePartDetailMessage(characterId: string, updates: SensitivePartDetailUpdate[]): string {\n  const lines = ['[编辑敏感部位详情]', `角色ID：${characterId}`];\n  for (const u of updates) {\n    const parts = [u.name];\n    if (u.level != null) parts.push(`敏感等级${u.level}`);\n    if (u.reaction) parts.push(`反应：${u.reaction}`);\n    if (u.devDetails) parts.push(`开发：${u.devDetails}`);\n    lines.push(`- ${parts.join('：')}`);\n  }\n  return lines.join('\\n');\n}\n\n/**\n * 格式化身份标签更新消息\n */\nexport function formatIdentityTagsMessage(characterId: string, tags: Record<string, string>): string {\n  const lines = ['[编辑身份标签]', `角色ID：${characterId}`];\n  for (const [category, value] of Object.entries(tags)) {\n    lines.push(`${category}：${value}`);\n  }\n  return lines.join('\\n');\n}\n\n// ---------- 世界规则 ----------\n\nexport function formatWorldRuleMessage(type: 'add' | 'edit' | 'archive' | 'restore', name: string, detail?: string): string {\n  if (type === 'archive') return `[归档世界规则]\\n名称：${name}`;\n  if (type === 'restore') return `[复原世界规则]\\n名称：${name}`;\n  const prefix = type === 'add' ? '[新增世界规则]' : '[编辑世界规则]';\n  return `${prefix}\\n名称：${name}\\n细节：${detail ?? ''}`;\n}\n\nexport function addWorldRuleToVariables(title: string, desc: string): void {\n  const store = useDataStore();\n  store.data.世界规则[title] = {\n    名称: title,\n    效果描述: desc,\n    状态: '生效中',\n    细分规则: {},\n    适用对象: '',\n    标记: '世界级',\n  };\n  bumpUpdateTime();\n}\n\nexport function updateWorldRuleInVariables(idOrTitle: string, updates: Partial<RuleData>): void {\n  const store = useDataStore();\n  const rules = store.data.世界规则;\n  \n  // 查找规则键\n  let key = idOrTitle;\n  if (!rules[idOrTitle] && idOrTitle.startsWith('world-')) {\n    const t = idOrTitle.slice('world-'.length);\n    if (rules[t]) key = t;\n  }\n  \n  if (!rules[key]) return;\n\n  const cur = rules[key];\n  const newTitle = updates.title?.trim();\n  \n  // 如果需要重命名\n  if (newTitle && newTitle !== key) {\n    delete rules[key];\n    rules[newTitle] = {\n      ...cur,\n      名称: newTitle,\n      效果描述: updates.desc ?? cur.效果描述,\n      状态: enRuleStatusToZh(updates.status, cur.状态),\n    };\n  } else {\n    cur.效果描述 = updates.desc ?? cur.效果描述;\n    cur.状态 = enRuleStatusToZh(updates.status, cur.状态);\n  }\n\n  bumpUpdateTime();\n}\n\nexport function archiveWorldRuleInVariables(idOrTitle: string): void {\n  const store = useDataStore();\n  const rules = store.data.世界规则;\n  \n  let key = idOrTitle;\n  if (!rules[idOrTitle] && idOrTitle.startsWith('world-')) {\n    const t = idOrTitle.slice('world-'.length);\n    if (rules[t]) key = t;\n  }\n  \n  if (rules[key]) {\n    rules[key].状态 = '已归档';\n    bumpUpdateTime();\n  }\n}\n\nexport function restoreWorldRuleInVariables(idOrTitle: string): void {\n  const store = useDataStore();\n  const rules = store.data.世界规则;\n  \n  let key = idOrTitle;\n  if (!rules[idOrTitle] && idOrTitle.startsWith('world-')) {\n    const t = idOrTitle.slice('world-'.length);\n    if (rules[t]) key = t;\n  }\n  \n  if (rules[key]) {\n    rules[key].状态 = '生效中';\n    bumpUpdateTime();\n  }\n}\n\nexport async function submitAddWorldRule(name: string, detail: string): Promise<string> {\n  const n = name.trim();\n  if (!n) {\n    toastr.warning('请输入规则名称');\n    return '';\n  }\n  const message = formatWorldRuleMessage('add', n, detail.trim());\n  addWorldRuleToVariables(n, detail.trim());\n\n  // 异步触发世界大势生成（不阻塞主流程）\n  setTimeout(() => {\n    generateWorldTrend(n, 'world', detail.trim()).then((success) => {\n      if (success) {\n        toastr.success(`已生成世界大势说明：${n}`);\n      }\n    }).catch(console.error);\n  }, 100);\n\n  return message;\n}\n\nexport async function submitEditWorldRule(idOrTitle: string, name: string, detail: string): Promise<string> {\n  const n = name.trim();\n  if (!n) {\n    toastr.warning('请输入规则名称');\n    return '';\n  }\n  const message = formatWorldRuleMessage('edit', n, detail.trim());\n  updateWorldRuleInVariables(idOrTitle, { title: n, desc: detail.trim() });\n\n  // 异步触发世界大势生成（不阻塞主流程）\n  setTimeout(() => {\n    generateWorldTrend(n, 'world', detail.trim()).catch(console.error);\n  }, 100);\n\n  return message;\n}\n\nexport async function submitArchiveWorldRule(name: string): Promise<void> {\n  const message = formatWorldRuleMessage('archive', name);\n  await sendToDialog(message);\n  archiveWorldRuleInVariables(name);\n  toastr.success(`已归档世界规则「${name}」并写入对话框`);\n}\n\nexport async function submitRestoreWorldRule(name: string): Promise<void> {\n  const message = formatWorldRuleMessage('restore', name);\n  await sendToDialog(message);\n  restoreWorldRuleInVariables(name);\n  toastr.success(`已复原世界规则「${name}」并写入对话框`);\n}\n\n// ---------- 区域规则 ----------\n\nexport function formatRegionRuleMessage(\n  type: 'add' | 'edit' | 'archive' | 'restore',\n  regionName: string,\n  detail?: string,\n  /** 新增区域时可选：首条细分规则的名称（写入对话框摘要用） */\n  ruleName?: string,\n): string {\n  if (type === 'archive') return `[归档区域规则]\\n区域：${regionName}${detail ? `\\n规则：${detail}` : ''}`;\n  if (type === 'restore') return `[复原区域规则]\\n区域：${regionName}${detail ? `\\n规则：${detail}` : ''}`;\n  const prefix = type === 'add' ? '[新增区域]' : '[编辑区域]';\n  const rn = ruleName?.trim();\n  if (rn) {\n    return `${prefix}\\n区域名称：${regionName}\\n规则名字：${rn}\\n规则细节：${detail ?? ''}`;\n  }\n  return `${prefix}\\n区域名称：${regionName}\\n规则细节：${detail ?? ''}`;\n}\n\nexport function addRegionToVariables(name: string, detail: string, firstRuleTitle?: string): void {\n  const store = useDataStore();\n  // 使用浅拷贝 + 替换整个对象的方式，确保响应式系统正确追踪\n  const regions = { ...store.data.区域规则 };\n  const trimmedTitle = firstRuleTitle?.trim() ?? '';\n  const 细分规则 = trimmedTitle\n    ? { [trimmedTitle]: { 描述: detail, 状态: '生效中' as const } }\n    : {};\n  regions[name] = {\n    名称: name,\n    效果描述: detail,\n    状态: '生效中',\n    细分规则,\n    适用对象: '',\n    标记: '',\n  };\n  store.data.区域规则 = regions;\n  bumpUpdateTime();\n}\n\nexport function updateRegionInVariables(idOrName: string, updates: Partial<RegionData>): void {\n  const store = useDataStore();\n  // 使用浅拷贝 + 替换整个对象的方式，确保响应式系统正确追踪\n  const regions = { ...store.data.区域规则 };\n  \n  let key = idOrName;\n  if (!regions[idOrName] && idOrName.startsWith('region-')) {\n    const n = idOrName.slice('region-'.length);\n    if (regions[n]) key = n;\n  }\n  \n  if (!regions[key]) return;\n\n  const cur = regions[key];\n  const newName = updates.name?.trim();\n  \n  if (newName && newName !== key) {\n    delete regions[key];\n    regions[newName] = {\n      ...cur,\n      名称: newName,\n      效果描述: updates.description ?? cur.效果描述,\n      状态: enRuleStatusToZh(updates.status, cur.状态),\n    };\n  } else {\n    regions[key] = {\n      ...cur,\n      效果描述: updates.description ?? cur.效果描述,\n      状态: enRuleStatusToZh(updates.status, cur.状态),\n    };\n  }\n  \n  store.data.区域规则 = regions;\n  bumpUpdateTime();\n}\n\nexport function archiveRegionInVariables(idOrName: string): void {\n  const store = useDataStore();\n  // 使用浅拷贝 + 替换整个对象的方式，确保响应式系统正确追踪\n  const regions = { ...store.data.区域规则 };\n  \n  let key = idOrName;\n  if (!regions[idOrName] && idOrName.startsWith('region-')) {\n    const n = idOrName.slice('region-'.length);\n    if (regions[n]) key = n;\n  }\n  \n  if (regions[key]) {\n    regions[key] = { ...regions[key], 状态: '已归档' };\n    store.data.区域规则 = regions;\n    bumpUpdateTime();\n  }\n}\n\nexport function restoreRegionInVariables(idOrName: string): void {\n  const store = useDataStore();\n  // 使用浅拷贝 + 替换整个对象的方式，确保响应式系统正确追踪\n  const regions = { ...store.data.区域规则 };\n  \n  let key = idOrName;\n  if (!regions[idOrName] && idOrName.startsWith('region-')) {\n    const n = idOrName.slice('region-'.length);\n    if (regions[n]) key = n;\n  }\n  \n  if (regions[key]) {\n    regions[key] = { ...regions[key], 状态: '生效中' };\n    store.data.区域规则 = regions;\n    bumpUpdateTime();\n  }\n}\n\nexport function addRegionalRuleToVariables(regionIdOrName: string, title: string, desc: string): void {\n  const store = useDataStore();\n  // 使用浅拷贝 + 替换整个对象的方式，确保响应式系统正确追踪\n  const regions = { ...store.data.区域规则 };\n  \n  let key = regionIdOrName;\n  if (!regions[regionIdOrName] && regionIdOrName.startsWith('region-')) {\n    const n = regionIdOrName.slice('region-'.length);\n    if (regions[n]) key = n;\n  }\n  \n  if (!regions[key]) return;\n\n  // 更新区域及其细分规则\n  const curRegion = regions[key];\n  regions[key] = {\n    ...curRegion,\n    细分规则: {\n      ...curRegion.细分规则,\n      [title]: {\n        描述: desc,\n        状态: '生效中',\n      },\n    },\n  };\n  \n  store.data.区域规则 = regions;\n  bumpUpdateTime();\n}\n\nexport function updateRegionalRuleInVariables(regionIdOrName: string, ruleIdOrTitle: string, updates: Partial<RuleData>): void {\n  const store = useDataStore();\n  // 使用浅拷贝 + 替换整个对象的方式，确保响应式系统正确追踪\n  const regions = { ...store.data.区域规则 };\n  \n  let regionKey = regionIdOrName;\n  if (!regions[regionIdOrName] && regionIdOrName.startsWith('region-')) {\n    const n = regionIdOrName.slice('region-'.length);\n    if (regions[n]) regionKey = n;\n  }\n  \n  if (!regions[regionKey]) return;\n  \n  const region = { ...regions[regionKey] };\n  const subRules = { ...region.细分规则 };\n  \n  // 查找子规则键\n  let subKey = ruleIdOrTitle;\n  const prefix = `regional-${regionKey}-`;\n  if (!subRules[ruleIdOrTitle]) {\n    if (ruleIdOrTitle.startsWith(prefix)) {\n      const k = ruleIdOrTitle.slice(prefix.length);\n      if (subRules[k]) subKey = k;\n    }\n  }\n  \n  if (!subRules[subKey]) return;\n\n  const cur = subRules[subKey];\n  \n  if (updates.title && updates.title !== subKey) {\n    delete subRules[subKey];\n    subRules[updates.title] = {\n      ...cur,\n      描述: updates.desc ?? cur.描述,\n      状态: enRuleStatusToZh(updates.status, cur.状态),\n    };\n  } else {\n    subRules[subKey] = {\n      ...cur,\n      描述: updates.desc ?? cur.描述,\n      状态: enRuleStatusToZh(updates.status, cur.状态),\n    };\n  }\n  \n  // 替换区域及其细分规则\n  regions[regionKey] = {\n    ...region,\n    细分规则: subRules,\n  };\n  store.data.区域规则 = regions;\n  bumpUpdateTime();\n}\n\nexport function archiveRegionalRuleInVariables(regionIdOrName: string, ruleIdOrTitle: string): void {\n  const store = useDataStore();\n  // 使用浅拷贝 + 替换整个对象的方式，确保响应式系统正确追踪\n  const regions = { ...store.data.区域规则 };\n  \n  let regionKey = regionIdOrName;\n  if (!regions[regionIdOrName] && regionIdOrName.startsWith('region-')) {\n    const n = regionIdOrName.slice('region-'.length);\n    if (regions[n]) regionKey = n;\n  }\n  \n  if (!regions[regionKey]) return;\n  \n  const region = { ...regions[regionKey] };\n  const subRules = { ...region.细分规则 };\n  \n  let subKey = ruleIdOrTitle;\n  const prefix = `regional-${regionKey}-`;\n  if (!subRules[ruleIdOrTitle]) {\n    if (ruleIdOrTitle.startsWith(prefix)) {\n      const k = ruleIdOrTitle.slice(prefix.length);\n      if (subRules[k]) subKey = k;\n    }\n  }\n  \n  if (subRules[subKey]) {\n    subRules[subKey] = { ...subRules[subKey], 状态: '已归档' };\n    regions[regionKey] = {\n      ...region,\n      细分规则: subRules,\n    };\n    store.data.区域规则 = regions;\n    bumpUpdateTime();\n  }\n}\n\nexport function restoreRegionalRuleInVariables(regionIdOrName: string, ruleIdOrTitle: string): void {\n  const store = useDataStore();\n  // 使用浅拷贝 + 替换整个对象的方式，确保响应式系统正确追踪\n  const regions = { ...store.data.区域规则 };\n  \n  let regionKey = regionIdOrName;\n  if (!regions[regionIdOrName] && regionIdOrName.startsWith('region-')) {\n    const n = regionIdOrName.slice('region-'.length);\n    if (regions[n]) regionKey = n;\n  }\n  \n  if (!regions[regionKey]) return;\n  \n  const region = { ...regions[regionKey] };\n  const subRules = { ...region.细分规则 };\n  \n  let subKey = ruleIdOrTitle;\n  const prefix = `regional-${regionKey}-`;\n  if (!subRules[ruleIdOrTitle]) {\n    if (ruleIdOrTitle.startsWith(prefix)) {\n      const k = ruleIdOrTitle.slice(prefix.length);\n      if (subRules[k]) subKey = k;\n    }\n  }\n  \n  if (subRules[subKey]) {\n    subRules[subKey] = { ...subRules[subKey], 状态: '生效中' };\n    regions[regionKey] = {\n      ...region,\n      细分规则: subRules,\n    };\n    store.data.区域规则 = regions;\n    bumpUpdateTime();\n  }\n}\n\nexport async function submitAddRegion(name: string, detail: string, firstRuleName?: string): Promise<string> {\n  const n = name.trim();\n  if (!n) {\n    toastr.warning('请输入区域名称');\n    return '';\n  }\n  const ruleTitle = (firstRuleName ?? '').trim();\n  const message = formatRegionRuleMessage('add', n, detail.trim(), ruleTitle || undefined);\n  addRegionToVariables(n, detail.trim(), ruleTitle || undefined);\n\n  // 异步触发世界大势生成（区域级别）\n  setTimeout(() => {\n    generateWorldTrend(n, 'regional', detail.trim(), [n]).then((success) => {\n      if (success) {\n        toastr.success(`已生成世界大势说明：${n}`);\n      }\n    }).catch(console.error);\n  }, 100);\n\n  return message;\n}\n\nexport async function submitAddRegionalRule(regionIdOrName: string, regionName: string, ruleName: string, ruleDetail: string): Promise<string> {\n  const n = ruleName.trim();\n  if (!n) {\n    toastr.warning('请输入规则名称');\n    return '';\n  }\n  const detail = ruleDetail.trim();\n  const message = `[新增区域规则]\\n区域：${regionName}\\n规则：${n}\\n细节：${detail}`;\n  addRegionalRuleToVariables(regionIdOrName, n, detail);\n\n  // 异步触发世界大势生成（区域级别）\n  setTimeout(() => {\n    generateWorldTrend(n, 'regional', detail, [regionName]).then((success) => {\n      if (success) {\n        toastr.success(`已生成世界大势说明：${n}`);\n      }\n    }).catch(console.error);\n  }, 100);\n\n  return message;\n}\n\nexport async function submitEditRegionalRule(\n  regionIdOrName: string,\n  regionName: string,\n  ruleIdOrTitle: string,\n  ruleName: string,\n  ruleDetail: string,\n): Promise<string> {\n  const n = ruleName.trim();\n  if (!n) {\n    toastr.warning('请输入规则名称');\n    return '';\n  }\n  const detail = ruleDetail.trim();\n  const message = `[编辑区域规则]\\n区域：${regionName}\\n规则：${n}\\n细节：${detail}`;\n  updateRegionalRuleInVariables(regionIdOrName, ruleIdOrTitle, { title: n, desc: detail });\n\n  // 异步触发世界大势生成（区域级别）\n  setTimeout(() => {\n    generateWorldTrend(n, 'regional', detail, [regionName]).catch(console.error);\n  }, 100);\n\n  return message;\n}\n\nexport async function submitEditRegion(idOrName: string, name: string, detail: string): Promise<string> {\n  const n = name.trim();\n  if (!n) {\n    toastr.warning('请输入区域名称');\n    return '';\n  }\n  const message = formatRegionRuleMessage('edit', n, detail.trim());\n  updateRegionInVariables(idOrName, { name: n, description: detail.trim() });\n\n  // 异步触发世界大势生成（区域级别）\n  setTimeout(() => {\n    generateWorldTrend(n, 'regional', detail.trim(), [n]).catch(console.error);\n  }, 100);\n\n  return message;\n}\n\nexport async function submitArchiveRegion(name: string): Promise<void> {\n  const message = formatRegionRuleMessage('archive', name);\n  await sendToDialog(message);\n  archiveRegionInVariables(name);\n  toastr.success(`已归档区域「${name}」并写入对话框`);\n}\n\nexport async function submitRestoreRegion(name: string): Promise<void> {\n  const message = formatRegionRuleMessage('restore', name);\n  await sendToDialog(message);\n  restoreRegionInVariables(name);\n  toastr.success(`已复原区域「${name}」并写入对话框`);\n}\n\nexport async function submitArchiveRegionalRule(regionName: string, ruleIdOrTitle: string, ruleSummary?: string): Promise<void> {\n  const message = formatRegionRuleMessage('archive', regionName, ruleSummary ?? ruleIdOrTitle);\n  await sendToDialog(message);\n  archiveRegionalRuleInVariables(regionName, ruleIdOrTitle);\n  toastr.success(`已归档「${regionName}」下规则${ruleSummary ? `「${ruleSummary}」` : ''}并写入对话框`);\n}\n\nexport async function submitRestoreRegionalRule(regionName: string, ruleIdOrTitle: string, ruleSummary?: string): Promise<void> {\n  const message = formatRegionRuleMessage('restore', regionName, ruleSummary ?? ruleIdOrTitle);\n  await sendToDialog(message);\n  restoreRegionalRuleInVariables(regionName, ruleIdOrTitle);\n  toastr.success(`已复原「${regionName}」下规则${ruleSummary ? `「${ruleSummary}」` : ''}并写入对话框`);\n}\n\n// ---------- 个人规则 ----------\n\nexport function formatPersonalRuleMessage(type: 'add' | 'edit' | 'archive' | 'restore', characterName: string, detail?: string): string {\n  if (type === 'archive') return `[归档个人规则]\\n对象：${characterName}${detail ? `\\n规则：${detail}` : ''}`;\n  if (type === 'restore') return `[复原个人规则]\\n对象：${characterName}${detail ? `\\n规则：${detail}` : ''}`;\n  const prefix = type === 'add' ? '[新增个人规则]' : '[编辑个人规则]';\n  return `${prefix}\\n对象：${characterName}\\n规则细节：${detail ?? ''}`;\n}\n\nexport function addPersonalRuleToVariables(characterName: string, detail: string): void {\n  const store = useDataStore();\n  const key = `PR-${Date.now()}`;\n  const c = characterName.trim();\n  store.data.个人规则[key] = {\n    名称: c,\n    适用对象: c,\n    效果描述: detail.trim(),\n    状态: '生效中',\n    细分规则: {},\n    标记: '个人级',\n  };\n  bumpUpdateTime();\n}\n\nexport function updatePersonalRuleInVariables(idOrTitle: string, updates: Partial<RuleData>): void {\n  const store = useDataStore();\n  const rules = store.data.个人规则;\n  \n  let key = idOrTitle;\n  if (!rules[idOrTitle] && idOrTitle.startsWith('personal-')) {\n    const k = idOrTitle.slice('personal-'.length);\n    if (rules[k]) key = k;\n  }\n  \n  if (!rules[key]) return;\n\n  const cur = rules[key];\n  \n  if (updates.title) {\n    cur.名称 = updates.title;\n    cur.适用对象 = updates.title;\n  }\n  if (updates.desc) cur.效果描述 = updates.desc;\n  cur.状态 = enRuleStatusToZh(updates.status, cur.状态);\n\n  bumpUpdateTime();\n}\n\nexport function archivePersonalRuleInVariables(idOrTitle: string): void {\n  const store = useDataStore();\n  const rules = store.data.个人规则;\n  \n  let key = idOrTitle;\n  if (!rules[idOrTitle] && idOrTitle.startsWith('personal-')) {\n    const k = idOrTitle.slice('personal-'.length);\n    if (rules[k]) key = k;\n  }\n  \n  if (rules[key]) {\n    rules[key].状态 = '已归档';\n    bumpUpdateTime();\n  }\n}\n\nexport function restorePersonalRuleInVariables(idOrTitle: string): void {\n  const store = useDataStore();\n  const rules = store.data.个人规则;\n  \n  let key = idOrTitle;\n  if (!rules[idOrTitle] && idOrTitle.startsWith('personal-')) {\n    const k = idOrTitle.slice('personal-'.length);\n    if (rules[k]) key = k;\n  }\n  \n  if (rules[key]) {\n    rules[key].状态 = '生效中';\n    bumpUpdateTime();\n  }\n}\n\nexport async function submitAddPersonalRule(characterName: string, detail: string): Promise<string> {\n  const c = characterName.trim();\n  if (!c) {\n    toastr.warning('请输入角色/对象名称');\n    return '';\n  }\n  const message = formatPersonalRuleMessage('add', c, detail.trim());\n  addPersonalRuleToVariables(c, detail.trim());\n\n  // 获取未出场角色列表（用于居民生活生成）\n  const store = useDataStore();\n  const inactiveChars = Object.entries(store.data.角色档案 || {})\n    .filter(([_, char]) => char.状态 !== '出场中')\n    .map(([id, char]) => char.姓名 || id);\n\n  // 异步触发居民生活生成\n  setTimeout(() => {\n    generateResidentLife(c, c, detail.trim(), inactiveChars).then((success) => {\n      if (success) {\n        toastr.success(`已生成居民生活说明：${c}`);\n      }\n    }).catch(console.error);\n  }, 100);\n\n  return message;\n}\n\nexport async function submitEditPersonalRule(idOrTitle: string, characterName: string, detail: string): Promise<string> {\n  const c = characterName.trim();\n  if (!c) {\n    toastr.warning('请输入角色/对象名称');\n    return '';\n  }\n  const message = formatPersonalRuleMessage('edit', c, detail.trim());\n  updatePersonalRuleInVariables(idOrTitle, { title: c, desc: detail.trim() });\n\n  // 获取未出场角色列表（用于居民生活生成）\n  const store = useDataStore();\n  const inactiveChars = Object.entries(store.data.角色档案 || {})\n    .filter(([_, char]) => char.状态 !== '出场中')\n    .map(([id, char]) => char.姓名 || id);\n\n  // 异步触发居民生活生成\n  setTimeout(() => {\n    generateResidentLife(c, c, detail.trim(), inactiveChars).catch(console.error);\n  }, 100);\n\n  return message;\n}\n\nexport async function submitArchivePersonalRule(idOrTitle: string, characterName?: string, ruleSummary?: string): Promise<void> {\n  const label = characterName ?? idOrTitle;\n  const message = formatPersonalRuleMessage('archive', label, ruleSummary);\n  await sendToDialog(message);\n  archivePersonalRuleInVariables(idOrTitle);\n  toastr.success(`已归档「${label}」${ruleSummary ? `（${ruleSummary}）` : ''}并写入对话框`);\n}\n\nexport async function submitRestorePersonalRule(idOrTitle: string, characterName?: string, ruleSummary?: string): Promise<void> {\n  const label = characterName ?? idOrTitle;\n  const message = formatPersonalRuleMessage('restore', label, ruleSummary);\n  await sendToDialog(message);\n  restorePersonalRuleInVariables(idOrTitle);\n  toastr.success(`已复原「${label}」${ruleSummary ? `（${ruleSummary}）` : ''}并写入对话框`);\n}\n\n// ---------- 世界书同步 ----------\n\n/**\n * 将当前回合的剧情摘要同步到世界书「编年史」条目\n * 由 App.vue 发送消息后调用，也由小手机壳的 REQUEST_TRIGGER_WB_SYNC 消息路由触发\n *\n * 流程：\n * 1. 从最新消息楼层读取 <sum> 标签内容（编年史Updater 已封装此逻辑）\n * 2. 读取 <maintext> 最近正文片段（用于生成更丰富的摘要）\n * 3. 调用编年史更新函数写入世界书\n */\nexport async function syncGameStoryToWorldbook(): Promise<void> {\n  try {\n    const { checkAndUpdateChronicle } = await import('./chronicleUpdater');\n    const success = await checkAndUpdateChronicle();\n    if (success) {\n      console.log('✅ [dialogAndVariable] 剧情摘要已同步到世界书「编年史」');\n    } else {\n      console.warn('⚠️ [dialogAndVariable] 剧情摘要同步失败（可能没有 <sum> 内容）');\n    }\n  } catch (e) {\n    console.warn('⚠️ [dialogAndVariable] 同步剧情到世界书失败:', e);\n  }\n}\n","/**\n * 将本地图片缩放并编码为较小体积的 Data URL（优先 WebP，其次 JPEG）。\n * 用于头像弹窗等需生成较小 Data URL 的场景（头像仅存本机时同样可用），避免 Base64 过大。\n */\n\nfunction estimateBytesFromDataUrl(dataUrl: string): number {\n  const base64 = dataUrl.split(',')[1] || '';\n  return Math.floor((base64.length * 3) / 4);\n}\n\n/** 检测当前环境是否可用 canvas 输出指定 MIME（WebP 在旧 Safari 上可能不可用） */\nfunction canEncodeMime(mime: string): boolean {\n  try {\n    const c = document.createElement('canvas');\n    c.width = 2;\n    c.height = 2;\n    const u = c.toDataURL(mime, 0.8);\n    return u.startsWith(`data:${mime}`);\n  } catch {\n    return false;\n  }\n}\n\nasync function fileToScaledCanvas(file: File, maxEdgePx: number): Promise<HTMLCanvasElement> {\n  const canvas = document.createElement('canvas');\n  const ctx = canvas.getContext('2d');\n  if (!ctx) throw new Error('Canvas 2D 不可用');\n\n  if (typeof createImageBitmap === 'function') {\n    const bmp = await createImageBitmap(file);\n    try {\n      const scale = Math.min(1, maxEdgePx / Math.max(bmp.width, bmp.height));\n      const w = Math.max(1, Math.round(bmp.width * scale));\n      const h = Math.max(1, Math.round(bmp.height * scale));\n      canvas.width = w;\n      canvas.height = h;\n      ctx.drawImage(bmp, 0, 0, w, h);\n      return canvas;\n    } finally {\n      bmp.close();\n    }\n  }\n\n  return new Promise((resolve, reject) => {\n    const img = new Image();\n    const url = URL.createObjectURL(file);\n    img.onload = () => {\n      try {\n        const scale = Math.min(1, maxEdgePx / Math.max(img.naturalWidth, img.naturalHeight));\n        const w = Math.max(1, Math.round(img.naturalWidth * scale));\n        const h = Math.max(1, Math.round(img.naturalHeight * scale));\n        canvas.width = w;\n        canvas.height = h;\n        ctx.drawImage(img, 0, 0, w, h);\n        resolve(canvas);\n      } catch (e) {\n        reject(e instanceof Error ? e : new Error(String(e)));\n      } finally {\n        URL.revokeObjectURL(url);\n      }\n    };\n    img.onerror = () => {\n      URL.revokeObjectURL(url);\n      reject(new Error('图片加载失败'));\n    };\n    img.src = url;\n  });\n}\n\nexport type CompressImageOptions = {\n  /** 长边最大像素，默认 512 */\n  maxEdgePx?: number;\n  /** 压缩后目标体积上限（解码后约等于字节数），默认 220KB */\n  maxOutputBytes?: number;\n};\n\n/**\n * 读取本地图片文件，按长边限制缩放，并优先输出 WebP，其次 JPEG，直到体积满足上限。\n */\nexport async function compressImageFileToDataUrl(\n  file: File,\n  options?: CompressImageOptions,\n): Promise<string> {\n  const maxEdgePx = options?.maxEdgePx ?? 512;\n  const maxOutputBytes = options?.maxOutputBytes ?? 220 * 1024;\n\n  const webpOk = canEncodeMime('image/webp');\n  const qualities = [0.9, 0.84, 0.78, 0.72, 0.65, 0.58, 0.5, 0.42];\n  const edges = [maxEdgePx, Math.round(maxEdgePx * 0.75), 384, 288, 256, 192, 160, 128];\n\n  for (const edge of edges) {\n    const canvas = await fileToScaledCanvas(file, edge);\n    for (const q of qualities) {\n      if (webpOk) {\n        const webp = canvas.toDataURL('image/webp', q);\n        if (webp.startsWith('data:image/webp') && estimateBytesFromDataUrl(webp) <= maxOutputBytes) {\n          return webp;\n        }\n      }\n      const jpeg = canvas.toDataURL('image/jpeg', q);\n      if (jpeg.startsWith('data:image/jpeg') && estimateBytesFromDataUrl(jpeg) <= maxOutputBytes) {\n        return jpeg;\n      }\n    }\n  }\n\n  const last = await fileToScaledCanvas(file, 96);\n  const fallback = last.toDataURL('image/jpeg', 0.82);\n  return fallback;\n}\n","/**\n * 本地设置管理工具\n * 使用浏览器 localStorage 持久化存储设置\n */\n\nimport type { OutputMode, SecondaryApiConfig, InputActionMode, OtherSettings } from '../types';\nimport type { UiLayoutSettings } from './uiLayoutLimits';\nimport { DEFAULT_SECONDARY_API_CONFIG } from './secondaryApiDefaults';\n\nfunction clampSecondaryRetriesLoaded(n: unknown): number {\n  const x = Math.floor(Number(n));\n  if (Number.isNaN(x)) return DEFAULT_SECONDARY_API_CONFIG.maxRetries;\n  return Math.min(10, Math.max(0, x));\n}\n\n/** localStorage 键名 */\nconst STORAGE_KEYS = {\n  outputMode: 'rule_modifier_output_mode',\n  secondaryApi: 'rule_modifier_secondary_api',\n  uiLayout: 'rule_modifier_ui_layout',\n  otherSettings: 'rule_modifier_other_settings',\n} as const;\n\n/** 默认界面布局设置 */\nconst DEFAULT_UI_LAYOUT: UiLayoutSettings = {\n  scale: 0.8,\n  maxWidth: 900,\n  maxHeight: 600,\n  heightMode: 'fit',\n};\n\n/**\n * 保存输出模式到 localStorage\n */\nexport function saveOutputMode(mode: OutputMode): void {\n  try {\n    localStorage.setItem(STORAGE_KEYS.outputMode, mode);\n  } catch (error) {\n    console.warn('⚠️ [localSettings] 保存输出模式失败:', error);\n  }\n}\n\n/**\n * 从 localStorage 加载输出模式\n */\nexport function loadOutputMode(): OutputMode {\n  try {\n    const saved = localStorage.getItem(STORAGE_KEYS.outputMode);\n    if (saved === 'single' || saved === 'dual') {\n      return saved;\n    }\n  } catch (error) {\n    console.warn('⚠️ [localSettings] 加载输出模式失败:', error);\n  }\n  return 'dual';\n}\n\n/**\n * 保存第二API配置到 localStorage\n */\nexport function saveSecondaryApiConfig(config: SecondaryApiConfig): void {\n  try {\n    localStorage.setItem(STORAGE_KEYS.secondaryApi, JSON.stringify(config));\n  } catch (error) {\n    console.warn('⚠️ [localSettings] 保存第二API配置失败:', error);\n  }\n}\n\n/**\n * 从 localStorage 加载第二API配置\n */\nexport function loadSecondaryApiConfig(): SecondaryApiConfig {\n  try {\n    const saved = localStorage.getItem(STORAGE_KEYS.secondaryApi);\n    if (saved) {\n      const parsed = JSON.parse(saved);\n      return {\n        ...DEFAULT_SECONDARY_API_CONFIG,\n        url: parsed.url ?? DEFAULT_SECONDARY_API_CONFIG.url,\n        key: parsed.key ?? DEFAULT_SECONDARY_API_CONFIG.key,\n        model: parsed.model ?? DEFAULT_SECONDARY_API_CONFIG.model,\n        maxRetries: clampSecondaryRetriesLoaded(parsed.maxRetries ?? DEFAULT_SECONDARY_API_CONFIG.maxRetries),\n        useTavernMainConnection: parsed.useTavernMainConnection ?? DEFAULT_SECONDARY_API_CONFIG.useTavernMainConnection,\n        tasks: {\n          includeVariableUpdate: parsed.tasks?.includeVariableUpdate ?? DEFAULT_SECONDARY_API_CONFIG.tasks.includeVariableUpdate,\n          includeWorldTrend: parsed.tasks?.includeWorldTrend ?? DEFAULT_SECONDARY_API_CONFIG.tasks.includeWorldTrend,\n          includeResidentLife: parsed.tasks?.includeResidentLife ?? DEFAULT_SECONDARY_API_CONFIG.tasks.includeResidentLife,\n        },\n      };\n    }\n  } catch (error) {\n    console.warn('⚠️ [localSettings] 加载第二API配置失败:', error);\n  }\n  return { ...DEFAULT_SECONDARY_API_CONFIG };\n}\n\n/**\n * 保存界面布局设置到 localStorage\n */\nexport function saveUiLayout(layout: UiLayoutSettings): void {\n  try {\n    localStorage.setItem(STORAGE_KEYS.uiLayout, JSON.stringify(layout));\n  } catch (error) {\n    console.warn('⚠️ [localSettings] 保存界面布局失败:', error);\n  }\n}\n\n/**\n * 从 localStorage 加载界面布局设置\n */\nexport function loadUiLayout(): UiLayoutSettings {\n  try {\n    const saved = localStorage.getItem(STORAGE_KEYS.uiLayout);\n    if (saved) {\n      const parsed = JSON.parse(saved);\n      return {\n        scale: Number(parsed.scale) || DEFAULT_UI_LAYOUT.scale,\n        maxWidth: Number(parsed.maxWidth) || DEFAULT_UI_LAYOUT.maxWidth,\n        maxHeight: Number(parsed.maxHeight) || DEFAULT_UI_LAYOUT.maxHeight,\n        heightMode: parsed.heightMode || DEFAULT_UI_LAYOUT.heightMode,\n      };\n    }\n  } catch (error) {\n    console.warn('⚠️ [localSettings] 加载界面布局失败:', error);\n  }\n  return { ...DEFAULT_UI_LAYOUT };\n}\n\n/**\n * 保存其他设置到 localStorage\n */\nexport function saveOtherSettingsLocal(settings: OtherSettings): void {\n  try {\n    localStorage.setItem(STORAGE_KEYS.otherSettings, JSON.stringify(settings));\n  } catch (error) {\n    console.warn('⚠️ [localSettings] 保存其他设置失败:', error);\n  }\n}\n\n/**\n * 从 localStorage 加载其他设置\n */\n/** 与 `types.DEFAULT_OTHER_SETTINGS` 保持一致（此处不引用 types 默认值，避免与 apiSettings 的循环依赖） */\nconst DEFAULT_OTHER_LOCAL: OtherSettings = {\n  inputActionMode: 'append',\n  enableShujukuManualUpdateAfterConfirm: true,\n};\n\nexport function loadOtherSettings(): OtherSettings {\n  try {\n    const saved = localStorage.getItem(STORAGE_KEYS.otherSettings);\n    if (saved) {\n      const parsed = JSON.parse(saved);\n      return {\n        inputActionMode: (parsed.inputActionMode as InputActionMode) || DEFAULT_OTHER_LOCAL.inputActionMode,\n        enableShujukuManualUpdateAfterConfirm:\n          typeof parsed.enableShujukuManualUpdateAfterConfirm === 'boolean'\n            ? parsed.enableShujukuManualUpdateAfterConfirm\n            : DEFAULT_OTHER_LOCAL.enableShujukuManualUpdateAfterConfirm,\n      };\n    }\n  } catch (error) {\n    console.warn('⚠️ [localSettings] 加载其他设置失败:', error);\n  }\n  return { ...DEFAULT_OTHER_LOCAL };\n}\n\n/**\n * 清除所有本地设置\n */\nexport function clearAllLocalSettings(): void {\n  try {\n    Object.values(STORAGE_KEYS).forEach((key) => {\n      localStorage.removeItem(key);\n    });\n    console.log('✅ [localSettings] 所有本地设置已清除');\n  } catch (error) {\n    console.warn('⚠️ [localSettings] 清除设置失败:', error);\n  }\n}\n\n/** 导出常量供外部使用（DEFAULT_OTHER_LOCAL 与 types.DEFAULT_OTHER_SETTINGS 一致） */\nexport { DEFAULT_UI_LAYOUT, DEFAULT_OTHER_LOCAL as DEFAULT_OTHER_SETTINGS, STORAGE_KEYS };\n","/**\n * 消息解析工具\n * 从最新楼层消息中解析 maintext 和 option 标签\n */\n\n/** ok：仅 1 开 1 闭（或可选标签未出现）；warning：多组闭合或开比闭多 1（仍可按最后一对解析）；error：未闭合或严重失衡 */\nexport type TagCheckSeverity = 'ok' | 'warning' | 'error';\n\n/**\n * 标签验证结果\n */\nexport interface TagCheckResult {\n  tag: string;\n  /** 是否可按最后一对标签正常解析（ok / warning 为 true；error 为 false） */\n  isValid: boolean;\n  severity: TagCheckSeverity;\n  isOpen: boolean;\n  isClosed: boolean;\n  message: string;\n}\n\n/** 多一个开标签、少一个闭标签：常见于正文前重复书写了格式示例（与预设/提示词有关） */\nexport function isSuspiciousDuplicateOpenMismatch(open: number, close: number): boolean {\n  return open === close + 1 && close >= 1;\n}\n\ntype TagKind = 'optionalAbsent' | 'required';\n\n/**\n * 标签检核着色：仅 1 开 1 闭为绿；多组闭合或开比闭恰好多 1 为黄（仍可按最后一对解析）；闭比开多、有开无闭、开比闭多 2+ 为红。\n */\nfunction classifyTagBalance(\n  tag: TagCheckResult['tag'],\n  open: number,\n  close: number,\n  kind: TagKind,\n): TagCheckResult {\n  const angle = tag === 'UpdateVariable' ? '<UpdateVariable>' : `<${tag}>`;\n\n  if (kind === 'optionalAbsent' && open === 0 && close === 0) {\n    const absentMsg =\n      tag === 'thinking'\n        ? '无 <thinking> 标签'\n        : tag === 'sum'\n          ? '无 <sum> 标签（可选）'\n          : '无 <UpdateVariable> 标签（可选）';\n    return {\n      tag,\n      isValid: true,\n      severity: 'ok',\n      isOpen: false,\n      isClosed: false,\n      message: absentMsg,\n    };\n  }\n\n  if (kind === 'required' && open === 0) {\n    return {\n      tag,\n      isValid: false,\n      severity: 'error',\n      isOpen: false,\n      isClosed: false,\n      message: tag === 'maintext' ? '缺少 <maintext> 标签' : '缺少 <option> 标签',\n    };\n  }\n\n  if (open < close) {\n    return {\n      tag,\n      isValid: false,\n      severity: 'error',\n      isOpen: true,\n      isClosed: true,\n      message: `${angle} 多余的闭标签（${open} 开 / ${close} 闭）`,\n    };\n  }\n\n  if (close === 0 && open > 0) {\n    return {\n      tag,\n      isValid: false,\n      severity: 'error',\n      isOpen: true,\n      isClosed: false,\n      message: `${angle} 未闭合（${open} 开 / 0 闭）`,\n    };\n  }\n\n  if (open === close) {\n    // option 标签：只要有一个闭合就算绿\n    if (tag === 'option' && close >= 1) {\n      return {\n        tag,\n        isValid: true,\n        severity: 'ok',\n        isOpen: true,\n        isClosed: true,\n        message: close === 1 ? `${angle} 仅 1 组开闭，正确` : `${angle} 共 ${open} 组开闭，正确`,\n      };\n    }\n    if (open === 1) {\n      return {\n        tag,\n        isValid: true,\n        severity: 'ok',\n        isOpen: true,\n        isClosed: true,\n        message: `${angle} 仅 1 组开闭，正确`,\n      };\n    }\n    return {\n      tag,\n      isValid: true,\n      severity: 'warning',\n      isOpen: true,\n      isClosed: true,\n      message: `${angle} 共 ${open} 组闭合；仅 1 组为绿，多组为黄（已按最后一对解析）`,\n    };\n  }\n\n  const extra = open - close;\n  if (extra === 1) {\n    return {\n      tag,\n      isValid: true,\n      severity: 'warning',\n      isOpen: true,\n      isClosed: true,\n      message: `${angle} 多 1 个开标签（${open} 开 / ${close} 闭），为黄（已按最后一对解析）`,\n    };\n  }\n\n  return {\n    tag,\n    isValid: false,\n    severity: 'error',\n    isOpen: true,\n    isClosed: false,\n    message: `${angle} 未正确闭合（${open} 开 / ${close} 闭），缺 ${extra} 个闭标签`,\n  };\n}\n\n/**\n * 验证消息中的标签闭合情况\n * 顺序：thinking → maintext → option → sum → UpdateVariable\n */\nexport function validateTags(messageContent: string): TagCheckResult[] {\n  if (!messageContent) {\n    return [\n      classifyTagBalance('thinking', 0, 0, 'optionalAbsent'),\n      classifyTagBalance('maintext', 0, 0, 'required'),\n      classifyTagBalance('option', 0, 0, 'required'),\n      classifyTagBalance('sum', 0, 0, 'optionalAbsent'),\n      classifyTagBalance('UpdateVariable', 0, 0, 'optionalAbsent'),\n    ];\n  }\n\n  const thinkingOpen = (messageContent.match(/<thinking>/gi) || []).length;\n  const thinkingClose = (messageContent.match(/<\\/thinking>/gi) || []).length;\n  const thinking = classifyTagBalance('thinking', thinkingOpen, thinkingClose, 'optionalAbsent');\n\n  const maintextOpen = (messageContent.match(/<maintext>/gi) || []).length;\n  const maintextClose = (messageContent.match(/<\\/maintext>/gi) || []).length;\n  const maintext = classifyTagBalance('maintext', maintextOpen, maintextClose, 'required');\n\n  const optionOpen = (messageContent.match(/<option/gi) || []).length;\n  const optionClose = (messageContent.match(/<\\/option>/gi) || []).length;\n  const option = classifyTagBalance('option', optionOpen, optionClose, 'required');\n\n  const sumOpen = (messageContent.match(/<sum>/gi) || []).length;\n  const sumClose = (messageContent.match(/<\\/sum>/gi) || []).length;\n  const sum = classifyTagBalance('sum', sumOpen, sumClose, 'optionalAbsent');\n\n  const uvOpen = (messageContent.match(/<UpdateVariable>/gi) || []).length;\n  const uvClose = (messageContent.match(/<\\/UpdateVariable>/gi) || []).length;\n  const updateVariable = classifyTagBalance('UpdateVariable', uvOpen, uvClose, 'optionalAbsent');\n\n  return [thinking, maintext, option, sum, updateVariable];\n}\n\n\n/**\n * 检查消息是否有未闭合的 thinking 或 redacted_reasoning 标签\n * 返回 true 表示所有过滤标签都已闭合，可以开始解析\n */\nexport function isFilteringComplete(messageContent: string): boolean {\n  if (!messageContent) return true;\n\n  // 检查 <thinking>\n  const thinkingOpen = (messageContent.match(/<thinking>/gi) || []).length;\n  const thinkingClose = (messageContent.match(/<\\/thinking>/gi) || []).length;\n  if (thinkingOpen > thinkingClose) return false;\n\n  // 检查 <redacted_reasoning>\n  const redactedOpen = (messageContent.match(/<redacted_reasoning>/gi) || []).length;\n  const redactedClose = (messageContent.match(/<\\/redacted_reasoning>/gi) || []).length;\n  if (redactedOpen > redactedClose) return false;\n\n  return true;\n}\n\n/**\n * 从流式文本中提取已过滤的内容（去除 thinking 和 redacted_reasoning 后）\n */\nexport function extractFilteredContent(streamText: string): string {\n  if (!streamText) return '';\n\n  // 移除所有已闭合的 <thinking> 标签及其内容\n  let cleaned = streamText.replace(/<thinking>.*?<\\/thinking>/gis, '');\n\n  // 移除所有已闭合的 <redacted_reasoning> 标签及其内容\n  cleaned = cleaned.replace(/<redacted_reasoning>.*?<\\/redacted_reasoning>/gis, '');\n\n  // 如果有未闭合的 <thinking> 标签，截断到该位置\n  const thinkingStart = cleaned.search(/<thinking>/i);\n  if (thinkingStart !== -1) {\n    cleaned = cleaned.substring(0, thinkingStart);\n  }\n\n  // 如果有未闭合的 <redacted_reasoning> 标签，截断到该位置\n  const redactedStart = cleaned.search(/<redacted_reasoning>/i);\n  if (redactedStart !== -1) {\n    cleaned = cleaned.substring(0, redactedStart);\n  }\n\n  return cleaned.trim();\n}\n\n/**\n * 从后往前配对：最后一个 </maintext> 与其前方最后一个 <maintext> 之间的内容。\n * 避免前文「1. <maintext>」等未闭合示例与唯一闭标签被非贪婪正则误配成一对。\n */\nexport function extractMaintextByLastClosePair(text: string): string {\n  if (!text) return '';\n\n  const lc = text.toLowerCase();\n  const closeIdx = lc.lastIndexOf('</maintext>');\n  if (closeIdx === -1) return '';\n\n  const openIdx = lc.lastIndexOf('<maintext>', closeIdx);\n  if (openIdx === -1) return '';\n\n  const openSlice = text.slice(openIdx);\n  const openMatch = openSlice.match(/^<maintext>/i);\n  if (!openMatch) return '';\n\n  const innerStart = openIdx + openMatch[0].length;\n  if (innerStart > closeIdx) return '';\n\n  if (!/^<\\/maintext>/i.test(text.slice(closeIdx))) return '';\n\n  return text.slice(innerStart, closeIdx).trim();\n}\n\n/**\n * 将「最后一对」<maintext> 的内部替换为 newInner，保留原有开闭标签写法（含大小写）。\n * 用于编辑保存，避免只替换到第一对标签。\n */\nexport function replaceLastMaintextInnerContent(fullMessage: string, newInner: string): string {\n  if (!fullMessage) return fullMessage;\n\n  const lc = fullMessage.toLowerCase();\n  const closeIdx = lc.lastIndexOf('</maintext>');\n  if (closeIdx === -1) return fullMessage;\n\n  const openIdx = lc.lastIndexOf('<maintext>', closeIdx);\n  if (openIdx === -1) return fullMessage;\n\n  const openMatch = fullMessage.slice(openIdx).match(/^<maintext>/i);\n  if (!openMatch) return fullMessage;\n\n  const innerStart = openIdx + openMatch[0].length;\n  if (innerStart > closeIdx) return fullMessage;\n\n  if (!/^<\\/maintext>/i.test(fullMessage.slice(closeIdx))) return fullMessage;\n\n  return fullMessage.slice(0, innerStart) + newInner + fullMessage.slice(closeIdx);\n}\n\n/**\n * 解析消息中的正文\n * 注意：先移除 <thinking> / redacted_reasoning，再按最后一对闭标签从后往前取 maintext\n */\nexport function parseMaintext(messageContent: string): string {\n  if (!messageContent) return '';\n\n  // 先移除所有<thinking>和标签及其内容\n  let cleaned = messageContent.replace(/<thinking>[\\s\\S]*?<\\/thinking>/gi, '');\n  cleaned = cleaned.replace(/<redacted_reasoning>[\\s\\S]*?<\\/redacted_reasoning>/gi, '');\n\n  // 检查是否有未闭合的标签\n  const thinkingStart = cleaned.search(/<thinking>/i);\n  if (thinkingStart !== -1) {\n    cleaned = cleaned.substring(0, thinkingStart);\n  }\n  const redactedStart = cleaned.search(/<redacted_reasoning>/i);\n  if (redactedStart !== -1) {\n    cleaned = cleaned.substring(0, redactedStart);\n  }\n\n  return extractMaintextByLastClosePair(cleaned);\n}\n\n/** 匹配 `<sum>` / `<sum …>` 或 `</sum>`，用于栈配对（只认完整闭合对） */\nconst SUM_PAIR_TOKEN_RE = /<sum(\\s[^>]*)?>|<\\/sum>/gi;\n\n/**\n * 提取「最后一个已闭合」的 `<sum>…</sum>` 内部文本：以文档中最后一个 `</sum>` 为准，与其栈配对的 `<sum>` 之间的内容。\n * 用栈配对，避免非贪婪正则把第一个 `</sum>` 错配给第一个 `<sum>`（例如示例 + 正文多段 sum 时）。\n */\nexport function extractLastSumContent(messageContent: string): string {\n  if (!messageContent) return '';\n  let cleaned = messageContent.replace(/<thinking>[\\s\\S]*?<\\/thinking>/gi, '');\n  cleaned = cleaned.replace(/<redacted_reasoning>[\\s\\S]*?<\\/redacted_reasoning>/gi, '');\n  const stack: number[] = [];\n  let lastClosedInner = '';\n  SUM_PAIR_TOKEN_RE.lastIndex = 0;\n  let m: RegExpExecArray | null;\n  while ((m = SUM_PAIR_TOKEN_RE.exec(cleaned)) !== null) {\n    const token = m[0];\n    if (/^<\\/sum>/i.test(token)) {\n      const contentStart = stack.pop();\n      if (contentStart !== undefined) {\n        lastClosedInner = cleaned.slice(contentStart, m.index).trim();\n      }\n    } else {\n      stack.push(m.index + token.length);\n    }\n  }\n  return lastClosedInner;\n}\n\n/**\n * 解析消息中的选项\n * 支持两种格式：\n * 1. 带 id: <option id=\"A\">选项文本</option>\n * 2. 不带 id: <option>\\nA. 选项1\\nB. 选项2\\n</option>\n */\nexport interface Option {\n  id: string;\n  text: string;\n}\n\nexport function parseOptions(messageContent: string): Option[] {\n  if (!messageContent) return [];\n\n  // 先移除 thinking 和 redacted_reasoning 标签\n  let cleaned = messageContent.replace(/<thinking>[\\s\\S]*?<\\/thinking>/gi, '');\n  cleaned = cleaned.replace(/<redacted_reasoning>[\\s\\S]*?<\\/redacted_reasoning>/gi, '');\n\n  const thinkingStart = cleaned.search(/<thinking>/i);\n  if (thinkingStart !== -1) {\n    cleaned = cleaned.substring(0, thinkingStart);\n  }\n  const redactedStart = cleaned.search(/<redacted_reasoning>/i);\n  if (redactedStart !== -1) {\n    cleaned = cleaned.substring(0, redactedStart);\n  }\n\n  // 匹配所有带 id 的 <option id=\"X\">...</option> 标签（支持多行内容）\n  const optionWithIdRegex = /<option id=\"([^\"]+)\">([\\s\\S]*?)<\\/option>/gi;\n  const optionsWithId: Option[] = [];\n  let match;\n  while ((match = optionWithIdRegex.exec(cleaned)) !== null) {\n    optionsWithId.push({\n      id: match[1].trim().toUpperCase(),\n      text: match[2].trim(),\n    });\n  }\n\n  // 如果找到带 id 的 option 标签，直接返回（通常是 A、B、C 三个选项）\n  if (optionsWithId.length > 0) {\n    return optionsWithId;\n  }\n\n  // 兼容旧格式：匹配所有不带 id 的 <option>...</option> 标签对\n  const optionPairRe = /<option([^>]*)>([\\s\\S]*?)<\\/option>/gi;\n  const allPairs = [...cleaned.matchAll(optionPairRe)];\n\n  // 取最后三个闭合的 <option>…</option> 标签对（通常对应 A/B/C 三个选项）\n  const lastThreePairs = allPairs.slice(-3);\n  const allOptionTexts: string[] = [];\n  for (const pair of lastThreePairs) {\n    const text = (pair[2] ?? '').trim();\n    if (text) allOptionTexts.push(text);\n  }\n  if (allOptionTexts.length === 0) {\n    return [];\n  }\n\n  const optionText = allOptionTexts.join('\\n');\n  const lines = optionText.split('\\n').map(line => line.trim()).filter(line => line.length > 0);\n\n  // 检查是否是 A.、B.、C. 格式\n  const optionPattern = /^[A-Z]\\.\\s*/;\n  const hasLetterPrefix = lines.some(line => optionPattern.test(line));\n\n  if (hasLetterPrefix) {\n    // 按字母开头分割选项\n    const options: Option[] = [];\n    let currentOption: string[] = [];\n\n    for (const line of lines) {\n      if (optionPattern.test(line)) {\n        if (currentOption.length > 0) {\n          const text = currentOption.join('\\n');\n          const id = text.match(/^([A-Z])\\./)?.[1] || String.fromCharCode(65 + options.length);\n          options.push({\n            id,\n            text: text.replace(/^[A-Z]\\.\\s*/, '').trim()\n          });\n          currentOption = [];\n        }\n        currentOption.push(line);\n      } else {\n        if (currentOption.length > 0) {\n          currentOption.push(line);\n        }\n      }\n    }\n\n    if (currentOption.length > 0) {\n      const text = currentOption.join('\\n');\n      const id = text.match(/^([A-Z])\\./)?.[1] || String.fromCharCode(65 + options.length);\n      options.push({\n        id,\n        text: text.replace(/^[A-Z]\\.\\s*/, '').trim()\n      });\n    }\n\n    return options;\n  } else {\n    // 单个选项或简单的多行选项\n    return lines.map((line, index) => ({\n      id: String.fromCharCode(65 + index),\n      text: line\n    }));\n  }\n}\n\n/**\n * 从最新 assistant 消息中读取正文和选项\n */\nexport function loadFromLatestMessage(): {\n  maintext: string;\n  options: Option[];\n  messageId?: number;\n  userMessageId?: number;\n  fullMessage?: string;\n} {\n  try {\n    const lastMessageId = getLastMessageId();\n    if (lastMessageId < 0) {\n      return { maintext: '', options: [] };\n    }\n\n    // 获取最新 assistant 消息\n    const messages = getChatMessages(lastMessageId, { role: 'assistant' });\n    if (!messages || messages.length === 0) {\n      // 尝试获取任意角色的最新消息\n      const allMessages = getChatMessages(lastMessageId);\n      if (!allMessages || allMessages.length === 0) {\n        return { maintext: '', options: [] };\n      }\n      const latestMessage = allMessages[0];\n      const maintext = parseMaintext(latestMessage.message || '');\n      const options = parseOptions(latestMessage.message || '');\n\n      // 查找对应的 user 消息（往前遍历，找到最近的一条 user 消息）\n      let userMessageId: number | undefined;\n      const msgId = latestMessage.message_id;\n      for (let i = msgId - 1; i >= 0; i--) {\n        const prevMessages = getChatMessages(i, { role: 'user' });\n        if (prevMessages && prevMessages.length > 0) {\n          userMessageId = prevMessages[0].message_id;\n          break;\n        }\n      }\n\n      return {\n        maintext,\n        options,\n        messageId: latestMessage.message_id,\n        userMessageId,\n        fullMessage: latestMessage.message\n      };\n    }\n\n    const latestAssistantMessage = messages[0];\n    const messageContent = latestAssistantMessage.message || '';\n\n    const maintext = parseMaintext(messageContent);\n    const options = parseOptions(messageContent);\n\n    // 查找对应的 user 消息（往前遍历，找到最近的一条 user 消息）\n    let userMessageId: number | undefined;\n    const assistantId = latestAssistantMessage.message_id;\n    for (let i = assistantId - 1; i >= 0; i--) {\n      const prevMessages = getChatMessages(i, { role: 'user' });\n      if (prevMessages && prevMessages.length > 0) {\n        userMessageId = prevMessages[0].message_id;\n        break;\n      }\n    }\n\n    return {\n      maintext,\n      options,\n      messageId: latestAssistantMessage.message_id,\n      userMessageId,\n      fullMessage: messageContent\n    };\n  } catch (error) {\n    console.error('❌ [messageParser] 加载最新消息失败:', error);\n    return { maintext: '', options: [] };\n  }\n}\n","/**\n * 其他设置管理工具\n * 管理输入行为模式等杂项设置\n */\n\nimport type { OtherSettings, InputActionMode } from '../types';\nimport { DEFAULT_OTHER_SETTINGS } from '../types';\nimport { useDataStore } from '../store';\nimport { loadOtherSettings, saveOtherSettingsLocal } from './localSettings';\n\nfunction readOtherFromLocalStorage(): OtherSettings | null {\n  try {\n    return loadOtherSettings();\n  } catch {\n    return null;\n  }\n}\n\n/**\n * 获取其他设置（MVU `player.settings.other` 优先，否则回退 localStorage）\n */\nexport function getOtherSettings(): OtherSettings {\n  const local = readOtherFromLocalStorage();\n  try {\n    const store = useDataStore();\n    const player = (store.data as any).player;\n    const settings = player?.settings?.other;\n\n    return {\n      inputActionMode:\n        settings?.inputActionMode ??\n        local?.inputActionMode ??\n        DEFAULT_OTHER_SETTINGS.inputActionMode,\n      enableShujukuManualUpdateAfterConfirm:\n        typeof settings?.enableShujukuManualUpdateAfterConfirm === 'boolean'\n          ? settings.enableShujukuManualUpdateAfterConfirm\n          : typeof local?.enableShujukuManualUpdateAfterConfirm === 'boolean'\n            ? local.enableShujukuManualUpdateAfterConfirm\n            : DEFAULT_OTHER_SETTINGS.enableShujukuManualUpdateAfterConfirm,\n    };\n  } catch (error) {\n    console.warn('⚠️ [otherSettings] 获取其他设置失败，使用默认值:', error);\n    return local ?? { ...DEFAULT_OTHER_SETTINGS };\n  }\n}\n\n/**\n * 保存其他设置（同时写入 MVU 与 localStorage，供 `getInputActionMode` 与界面一致）\n * 传入部分字段时会与当前设置合并，避免覆盖未传入的项。\n */\nexport function saveOtherSettings(partial: Partial<OtherSettings>): boolean {\n  const settings: OtherSettings = {\n    ...getOtherSettings(),\n    ...partial,\n  };\n  try {\n    saveOtherSettingsLocal(settings);\n\n    const store = useDataStore();\n\n    if (!(store.data as any).player) {\n      (store.data as any).player = { name: '玩家', settings: {} };\n    }\n    if (!(store.data as any).player.settings) {\n      (store.data as any).player.settings = {};\n    }\n    (store.data as any).player.settings.other = settings;\n\n    console.log('✅ [otherSettings] 设置已保存:', settings);\n    return true;\n  } catch (error) {\n    console.error('❌ [otherSettings] 保存设置失败:', error);\n    return false;\n  }\n}\n\n/**\n * 设置输入行为模式\n * @param mode 模式：'send' 直接发送，'append' 追加到输入框\n * @returns 是否成功\n */\nexport function setInputActionMode(mode: InputActionMode): boolean {\n  return saveOtherSettings({ inputActionMode: mode });\n}\n\n/** 是否在本界面确认标签并写入 AI 楼层后调用神·数据库「立即手动更新」 */\nexport function getEnableShujukuManualUpdateAfterConfirm(): boolean {\n  return getOtherSettings().enableShujukuManualUpdateAfterConfirm;\n}\n\n/**\n * 获取当前输入行为模式\n * @returns 当前模式\n */\nexport function getInputActionMode(): InputActionMode {\n  const settings = getOtherSettings();\n  return settings.inputActionMode;\n}\n\n/**\n * 切换输入行为模式\n * @returns 切换后的模式\n */\nexport function toggleInputActionMode(): InputActionMode {\n  const current = getInputActionMode();\n  const next = current === 'send' ? 'append' : 'send';\n  setInputActionMode(next);\n  return next;\n}\n","/**\n * 第二 API 默认配置（独立文件，供 localSettings / apiSettings 共用，避免循环依赖）\n */\nimport type { SecondaryApiConfig } from '../types';\n\nexport const DEFAULT_SECONDARY_API_CONFIG: SecondaryApiConfig = {\n  url: '',\n  key: '',\n  model: '',\n  maxRetries: 2,\n  useTavernMainConnection: true,\n  tasks: {\n    includeVariableUpdate: true,\n    includeWorldTrend: false,\n    includeResidentLife: false,\n  },\n};\n","/**\n * 性格：Record<名称, 描述字符串>；兼容 string[]。\n * 性癖 / 敏感部位：Record<名称, 嵌套对象>；兼容旧版「名→描述」纯字符串、string[]、JSON 字符串。\n */\n\nfunction tryParseJsonObject(raw: string): Record<string, unknown> | null {\n  const s = raw.trim();\n  if (!s.startsWith('{') || !s.endsWith('}')) return null;\n  try {\n    const v = JSON.parse(s) as unknown;\n    if (v && typeof v === 'object' && !Array.isArray(v)) return v as Record<string, unknown>;\n  } catch {\n    /* ignore */\n  }\n  return null;\n}\n\nfunction isCorruptObjectString(s: string): boolean {\n  return s === '[object Object]' || s.startsWith('[object ');\n}\n\n/** 性癖单条（中文键，与 MVU / 详情编辑一致） */\nexport interface FetishEntryZh {\n  等级: number;\n  细节描述: string;\n  自我合理化: string;\n}\n\n/** 敏感部位单条 */\nexport interface SensitiveEntryZh {\n  敏感等级: number;\n  生理反应: string;\n  开发细节: string;\n}\n\nfunction coerceFetishEntry(v: Record<string, unknown>): FetishEntryZh {\n  const level = v['等级'] ?? v['level'];\n  const n = typeof level === 'number' && Number.isFinite(level) ? level : Number(level);\n  const 等级 = Number.isFinite(n) ? Math.max(0, Math.min(10, Math.round(n))) : 1;\n  return {\n    等级,\n    细节描述: String(v['细节描述'] ?? v['description'] ?? ''),\n    自我合理化: String(v['自我合理化'] ?? v['justification'] ?? ''),\n  };\n}\n\nfunction coerceSensitiveEntry(v: Record<string, unknown>): SensitiveEntryZh {\n  const level = v['敏感等级'] ?? v['level'];\n  const n = typeof level === 'number' && Number.isFinite(level) ? level : Number(level);\n  const 敏感等级 = Number.isFinite(n) ? Math.max(0, Math.min(10, Math.round(n))) : 1;\n  return {\n    敏感等级,\n    生理反应: String(v['生理反应'] ?? v['reaction'] ?? ''),\n    开发细节: String(v['开发细节'] ?? v['devDetails'] ?? ''),\n  };\n}\n\n/**\n * 将任意存档形态规范为「名 → { 等级, 细节描述, 自我合理化 }」。\n * 禁止对 object 使用 String()，避免 \"[object Object]\" 污染 MVU。\n */\nexport function normalizeFetishRecord(raw: unknown): Record<string, FetishEntryZh> {\n  if (raw == null) return {};\n  if (Array.isArray(raw)) {\n    const o: Record<string, FetishEntryZh> = {};\n    raw.forEach((item, i) => {\n      const s = String(item ?? '');\n      const m = s.match(/^([^：:]+)[：:]\\s*(.*)$/);\n      if (m) {\n        o[m[1].trim()] = { 等级: 1, 细节描述: m[2].trim(), 自我合理化: '' };\n      } else {\n        o[`标签${i + 1}`] = { 等级: 1, 细节描述: s, 自我合理化: '' };\n      }\n    });\n    return o;\n  }\n  let obj: Record<string, unknown> | null = null;\n  if (typeof raw === 'object') {\n    obj = raw as Record<string, unknown>;\n  } else if (typeof raw === 'string') {\n    const parsed = tryParseJsonObject(raw);\n    obj = parsed;\n  }\n  if (!obj) return {};\n\n  const out: Record<string, FetishEntryZh> = {};\n  for (const [k, v] of Object.entries(obj)) {\n    const key = String(k);\n    if (v == null) continue;\n    if (typeof v === 'string') {\n      if (isCorruptObjectString(v)) {\n        out[key] = { 等级: 1, 细节描述: '', 自我合理化: '' };\n        continue;\n      }\n      const jp = tryParseJsonObject(v);\n      if (jp) {\n        out[key] = coerceFetishEntry(jp);\n        continue;\n      }\n      out[key] = { 等级: 1, 细节描述: v, 自我合理化: '' };\n      continue;\n    }\n    if (typeof v === 'object' && !Array.isArray(v)) {\n      out[key] = coerceFetishEntry(v as Record<string, unknown>);\n    }\n  }\n  return out;\n}\n\n/** 将任意存档形态规范为「名 → { 敏感等级, 生理反应, 开发细节 }」。 */\nexport function normalizeSensitivePartRecord(raw: unknown): Record<string, SensitiveEntryZh> {\n  if (raw == null) return {};\n  if (Array.isArray(raw)) {\n    const o: Record<string, SensitiveEntryZh> = {};\n    raw.forEach((item, i) => {\n      const s = String(item ?? '');\n      const m = s.match(/^([^：:]+)[：:]\\s*(.*)$/);\n      if (m) {\n        o[m[1].trim()] = { 敏感等级: 1, 生理反应: m[2].trim(), 开发细节: '' };\n      } else {\n        o[`标签${i + 1}`] = { 敏感等级: 1, 生理反应: s, 开发细节: '' };\n      }\n    });\n    return o;\n  }\n  let obj: Record<string, unknown> | null = null;\n  if (typeof raw === 'object') {\n    obj = raw as Record<string, unknown>;\n  } else if (typeof raw === 'string') {\n    const parsed = tryParseJsonObject(raw);\n    obj = parsed;\n  }\n  if (!obj) return {};\n\n  const out: Record<string, SensitiveEntryZh> = {};\n  for (const [k, v] of Object.entries(obj)) {\n    const key = String(k);\n    if (v == null) continue;\n    if (typeof v === 'string') {\n      if (isCorruptObjectString(v)) {\n        out[key] = { 敏感等级: 1, 生理反应: '', 开发细节: '' };\n        continue;\n      }\n      const jp = tryParseJsonObject(v);\n      if (jp) {\n        out[key] = coerceSensitiveEntry(jp);\n        continue;\n      }\n      out[key] = { 敏感等级: 1, 生理反应: v, 开发细节: '' };\n      continue;\n    }\n    if (typeof v === 'object' && !Array.isArray(v)) {\n      out[key] = coerceSensitiveEntry(v as Record<string, unknown>);\n    }\n  }\n  return out;\n}\n\n/** 性癖嵌套对象 → 多行文案（供弹窗编辑） */\nexport function fetishRecordToEditableText(field: unknown): string {\n  const n = normalizeFetishRecord(field);\n  return Object.entries(n)\n    .map(([k, o]) => {\n      const d = o.细节描述.trim();\n      const j = o.自我合理化.trim();\n      let line = `${k}：Lv.${o.等级}`;\n      if (d) line += ` ${d}`;\n      if (j) line += `｜${j}`;\n      return line;\n    })\n    .join('\\n');\n}\n\n/** 敏感部位嵌套对象 → 多行文案 */\nexport function sensitiveRecordToEditableText(field: unknown): string {\n  const n = normalizeSensitivePartRecord(field);\n  return Object.entries(n)\n    .map(([k, o]) => {\n      const r = o.生理反应.trim();\n      const d = o.开发细节.trim();\n      let line = `${k}：Lv.${o.敏感等级}`;\n      if (r) line += ` ${r}`;\n      if (d) line += `｜${d}`;\n      return line;\n    })\n    .join('\\n');\n}\n\n/** 归一化为 Record（供 Zod preprocess、store、variableReader 共用） */\nexport function normalizeTagMap(raw: unknown): Record<string, string> {\n  if (raw == null) return {};\n  if (Array.isArray(raw)) {\n    const o: Record<string, string> = {};\n    raw.forEach((item, i) => {\n      const s = String(item ?? '');\n      const m = s.match(/^([^：:]+)[：:]\\s*(.*)$/);\n      if (m) o[m[1].trim()] = m[2].trim();\n      else o[`标签${i + 1}`] = s;\n    });\n    return o;\n  }\n  if (typeof raw === 'object') {\n    const o: Record<string, string> = {};\n    for (const [k, v] of Object.entries(raw as Record<string, unknown>)) {\n      o[String(k)] = v == null ? '' : String(v);\n    }\n    return o;\n  }\n  return {};\n}\n\n/** 弹窗多行编辑：每行「名称：描述」或单独一行描述 */\nexport function parseEditableTextToTagMap(text: string): Record<string, string> {\n  const raw = String(text ?? '');\n  const lines = raw\n    .split(/\\r?\\n/)\n    .map(s => s.trim())\n    .filter(s => s.length > 0);\n  const o: Record<string, string> = {};\n  lines.forEach((line, i) => {\n    const m = line.match(/^([^：:]+)[：:]\\s*(.*)$/);\n    if (m) o[m[1].trim()] = m[2].trim();\n    else o[`标签${i + 1}`] = line;\n  });\n  return o;\n}\n\n/** 多行编辑 → 性癖嵌套对象（每行「名称：描述」） */\nexport function parseEditableTextToFetishRecord(text: string): Record<string, FetishEntryZh> {\n  return normalizeFetishRecord(parseEditableTextToTagMap(text));\n}\n\n/** 多行编辑 → 敏感部位嵌套对象 */\nexport function parseEditableTextToSensitiveRecord(text: string): Record<string, SensitiveEntryZh> {\n  return normalizeSensitivePartRecord(parseEditableTextToTagMap(text));\n}\n\n/** 变量 / Record → 弹窗多行文案 */\nexport function tagMapToEditableText(field: unknown): string {\n  if (field == null) return '';\n  if (Array.isArray(field)) return field.join('\\n');\n  if (typeof field === 'object') {\n    return Object.entries(field as Record<string, string>)\n      .map(([k, v]) => (String(v).trim() ? `${k}：${v}` : k))\n      .join('\\n');\n  }\n  return '';\n}\n\n/** Badge 列表：对象展平为「键：值」，数组保持原样字符串 */\nexport function tagFieldToBadgeLines(field: unknown): string[] {\n  if (field == null) return [];\n  if (Array.isArray(field)) return field.map(s => String(s));\n  if (typeof field === 'object') {\n    return Object.entries(field as Record<string, string>).map(([k, v]) =>\n      String(v).trim() ? `${k}：${v}` : k,\n    );\n  }\n  return [];\n}\n\n/** 三围：字符串 / 数字 / { B,W,H } 与更新规则、AI 输出对齐 */\nexport function normalize三围(raw: unknown): string {\n  if (raw == null || raw === '') return '未知';\n  if (typeof raw === 'string') return raw;\n  if (typeof raw === 'number' && Number.isFinite(raw)) return String(raw);\n  if (typeof raw === 'object' && raw !== null) {\n    const o = raw as Record<string, unknown>;\n    const B = o.B ?? o.b;\n    const W = o.W ?? o.w;\n    const H = o.H ?? o.h;\n    if (B != null && W != null && H != null) return `B${B} W${W} H${H}`;\n  }\n  return '未知';\n}\n","/**\n * 世界大势和居民生活独立存储管理\n * 使用localStorage，按聊天文件隔离\n */\n\n// Storage key generators - using chat ID to isolate data per chat file\nconst STORAGE_KEYS = {\n  worldTrend: (chatId: string) => `th_world_trend_${chatId}`,\n  residentLife: (chatId: string) => `th_resident_life_${chatId}`,\n};\n\n// Maximum number of records to keep\nconst MAX_RECORDS = 50;\n\n// Get current chat ID from SillyTavern\nfunction getCurrentChatId(): string {\n  return SillyTavern.getCurrentChatId?.() || 'default';\n}\n\n// ==================== Type Definitions ====================\n\n/**\n * 世界大势记录结构\n */\nexport interface WorldTrendRecord {\n  id: string; // timestamp + random\n  timestamp: number;\n  triggerRule: string; // 触发规则名称\n  ruleLevel: 'world' | 'regional'; // 世界或区域级\n  affectedScope: string; // 影响范围描述\n  dailyLifeChanges: string; // 日常生活变化描述\n  randomNpcCase: {\n    name: string;\n    identity: string;\n    lifeChange: string;\n    psychological: string;\n  };\n  isRead: boolean;\n}\n\n/**\n * 居民生活记录结构\n */\nexport interface ResidentLifeRecord {\n  id: string;\n  timestamp: number;\n  triggerRule: string; // 触发规则名称\n  targetCharacter: string; // 规则目标角色\n  otherCharacters: Array<{\n    name: string;\n    status: 'inactive' | 'retired'; // 未出场/暂时退场\n    lifeDescription: string;\n    abnormalChange: string; // 异常变化（如果有）\n  }>;\n  isRead: boolean;\n}\n\n// ==================== World Trend Records ====================\n\n/**\n * 加载世界大势记录\n */\nexport function loadWorldTrendRecords(): WorldTrendRecord[] {\n  const chatId = getCurrentChatId();\n  const key = STORAGE_KEYS.worldTrend(chatId);\n  const data = localStorage.getItem(key);\n  if (!data) return [];\n  try {\n    return JSON.parse(data);\n  } catch {\n    return [];\n  }\n}\n\n/**\n * 保存世界大势记录\n */\nexport function saveWorldTrendRecord(record: WorldTrendRecord): void {\n  const records = loadWorldTrendRecords();\n  records.unshift(record); // New records at the front\n\n  // Limit to max records\n  if (records.length > MAX_RECORDS) {\n    records.pop();\n  }\n\n  const chatId = getCurrentChatId();\n  localStorage.setItem(STORAGE_KEYS.worldTrend(chatId), JSON.stringify(records));\n}\n\n/**\n * 标记世界大势记录为已读\n */\nexport function markWorldTrendAsRead(recordId: string): void {\n  const records = loadWorldTrendRecords();\n  const record = records.find((r) => r.id === recordId);\n  if (record) {\n    record.isRead = true;\n  }\n\n  const chatId = getCurrentChatId();\n  localStorage.setItem(STORAGE_KEYS.worldTrend(chatId), JSON.stringify(records));\n}\n\n/**\n * 标记所有世界大势记录为已读\n */\nexport function markAllWorldTrendAsRead(): void {\n  const records = loadWorldTrendRecords();\n  records.forEach((r) => {\n    r.isRead = true;\n  });\n\n  const chatId = getCurrentChatId();\n  localStorage.setItem(STORAGE_KEYS.worldTrend(chatId), JSON.stringify(records));\n}\n\n/**\n * 获取未读世界大势记录数量\n */\nexport function getUnreadWorldTrendCount(): number {\n  return loadWorldTrendRecords().filter((r) => !r.isRead).length;\n}\n\n// ==================== Resident Life Records ====================\n\n/**\n * 加载居民生活记录\n */\nexport function loadResidentLifeRecords(): ResidentLifeRecord[] {\n  const chatId = getCurrentChatId();\n  const key = STORAGE_KEYS.residentLife(chatId);\n  const data = localStorage.getItem(key);\n  if (!data) return [];\n  try {\n    return JSON.parse(data);\n  } catch {\n    return [];\n  }\n}\n\n/**\n * 保存居民生活记录\n */\nexport function saveResidentLifeRecord(record: ResidentLifeRecord): void {\n  const records = loadResidentLifeRecords();\n  records.unshift(record); // New records at the front\n\n  // Limit to max records\n  if (records.length > MAX_RECORDS) {\n    records.pop();\n  }\n\n  const chatId = getCurrentChatId();\n  localStorage.setItem(STORAGE_KEYS.residentLife(chatId), JSON.stringify(records));\n}\n\n/**\n * 标记居民生活记录为已读\n */\nexport function markResidentLifeAsRead(recordId: string): void {\n  const records = loadResidentLifeRecords();\n  const record = records.find((r) => r.id === recordId);\n  if (record) {\n    record.isRead = true;\n  }\n\n  const chatId = getCurrentChatId();\n  localStorage.setItem(STORAGE_KEYS.residentLife(chatId), JSON.stringify(records));\n}\n\n/**\n * 标记所有居民生活记录为已读\n */\nexport function markAllResidentLifeAsRead(): void {\n  const records = loadResidentLifeRecords();\n  records.forEach((r) => {\n    r.isRead = true;\n  });\n\n  const chatId = getCurrentChatId();\n  localStorage.setItem(STORAGE_KEYS.residentLife(chatId), JSON.stringify(records));\n}\n\n/**\n * 获取未读居民生活记录数量\n */\nexport function getUnreadResidentLifeCount(): number {\n  return loadResidentLifeRecords().filter((r) => !r.isRead).length;\n}\n\n// ==================== Utility Functions ====================\n\n/**\n * 清除当前聊天的所有世界大势和居民生活记录\n */\nexport function clearAllWorldLifeRecords(): void {\n  const chatId = getCurrentChatId();\n  localStorage.removeItem(STORAGE_KEYS.worldTrend(chatId));\n  localStorage.removeItem(STORAGE_KEYS.residentLife(chatId));\n  console.log('[WorldLife] 已清除所有记录');\n}\n\n/**\n * 检查当前聊天是否有任何记录\n */\nexport function hasWorldLifeRecords(): boolean {\n  const worldRecords = loadWorldTrendRecords();\n  const residentRecords = loadResidentLifeRecords();\n  return worldRecords.length > 0 || residentRecords.length > 0;\n}\n\n/**\n * 获取总未读数量\n */\nexport function getTotalUnreadCount(): number 