          toastr.info('角色库中已有相同条目');\n                return;\n            }\n            characterSnippets.value.push({\n                id: createStorageId(),\n                name: char.name,\n                gender: char.gender,\n                desc: char.desc,\n            });\n            toastr.success('已加入角色库');\n        }\n        function addCharacterFromLibrary(s) {\n            characters.value.push({\n                name: s.name,\n                gender: s.gender,\n                desc: s.desc,\n            });\n            toastr.success('已添加角色');\n        }\n        function removeCharacterSnippet(id) {\n            characterSnippets.value = characterSnippets.value.filter(x => x.id !== id);\n            toastr.success('已从角色库删除');\n        }\n        function autoSnippetTitle(text, maxLen = 40) {\n            const t = text.trim();\n            const firstLine = (t.split(/\\r?\\n/)[0] ?? t).trim();\n            if (!firstLine)\n                return '未命名';\n            return firstLine.length > maxLen ? `${firstLine.slice(0, maxLen)}…` : firstLine;\n        }\n        function sceneBodyKey(body) {\n            return body.trim();\n        }\n        function saveNewSceneToLibrary() {\n            const body = customSceneDesc.value.trim();\n            if (!body) {\n                toastr.warning('请先在「或创建自定义场景」中填写描述');\n                return;\n            }\n            const key = sceneBodyKey(body);\n            if (sceneSnippets.value.some(s => sceneBodyKey(s.desc) === key)) {\n                toastr.info('场景库中已有相同文案');\n                return;\n            }\n            sceneSnippets.value.push({\n                id: createStorageId(),\n                name: autoSnippetTitle(body),\n                desc: body,\n            });\n            toastr.success('已加入场景库');\n        }\n        function addSceneFromLibrary(s) {\n            selectedScene.value = null;\n            customSceneDesc.value = s.desc;\n            sceneSnippetPickerOpen.value = false;\n            toastr.success('已取用场景');\n        }\n        function removeSceneSnippet(id) {\n            sceneSnippets.value = sceneSnippets.value.filter(x => x.id !== id);\n            toastr.success('已从场景库删除');\n        }\n        function saveNewOpeningSceneToLibrary() {\n            const body = openingSceneDetail.value.trim();\n            if (!body) {\n                toastr.warning('请先填写开局场景描述');\n                return;\n            }\n            const key = sceneBodyKey(body);\n            if (openingSceneSnippets.value.some(s => sceneBodyKey(s.desc) === key)) {\n                toastr.info('开局场景库中已有相同文案');\n                return;\n            }\n            openingSceneSnippets.value.push({\n                id: createStorageId(),\n                name: autoSnippetTitle(body),\n                desc: body,\n            });\n            toastr.success('已加入开局场景库');\n        }\n        function addOpeningSceneFromLibrary(s) {\n            openingSceneDetail.value = s.desc;\n            openingSceneSnippetPickerOpen.value = false;\n            toastr.success('已取用开局场景');\n        }\n        function removeOpeningSceneSnippet(id) {\n            openingSceneSnippets.value = openingSceneSnippets.value.filter(x => x.id !== id);\n            toastr.success('已从开局场景库删除');\n        }\n        function confirmSavePreset() {\n            const name = presetSaveName.value.trim();\n            if (!name) {\n                toastr.warning('请填写预设名称');\n                return;\n            }\n            presets.value.push({\n                id: createStorageId(),\n                name,\n                createdAt: new Date().toISOString(),\n                payload: capturePresetPayload(),\n            });\n            presetSaveName.value = '';\n            savePresetDialogOpen.value = false;\n            toastr.success('开场预设已保存');\n        }\n        function applyOpeningPreset(p) {\n            applyPresetPayload(p.payload);\n            presetPickerOpen.value = false;\n            toastr.success(`已应用预设：${p.name}`);\n            // 应用预设后直接跳转到确认页（最后一页）\n            goToPage('confirm');\n        }\n        function removePreset(id) {\n            presets.value = presets.value.filter(x => x.id !== id);\n            toastr.success('已删除预设');\n        }\n        function onExportJson() {\n            downloadOpeningStorageJson({\n                version: 1,\n                ruleSnippets: ruleSnippets.value,\n                characterSnippets: characterSnippets.value,\n                sceneSnippets: sceneSnippets.value,\n                openingSceneSnippets: openingSceneSnippets.value,\n                presets: presets.value,\n            });\n            toastr.success('已开始下载 JSON 文件');\n        }\n        function onPickImportJson() {\n            importFileInputRef.value?.click();\n        }\n        function onImportFileChange(ev) {\n            const input = ev.target;\n            const file = input.files?.[0];\n            input.value = '';\n            if (!file)\n                return;\n            const reader = new FileReader();\n            reader.onload = () => {\n                const text = typeof reader.result === 'string' ? reader.result : '';\n                const parsed = parseOpeningStorageJson(text);\n                if (!parsed) {\n                    toastr.error('JSON 格式无效或版本不匹配');\n                    return;\n                }\n                if (!window.confirm('将用文件中的规则库、角色库、场景库、开局场景库与开场预设完全替换当前浏览器中的数据，是否继续？')) {\n                    return;\n                }\n                ruleSnippets.value = parsed.ruleSnippets;\n                characterSnippets.value = parsed.characterSnippets;\n                sceneSnippets.value = parsed.sceneSnippets;\n                openingSceneSnippets.value = parsed.openingSceneSnippets;\n                presets.value = parsed.presets;\n                persistOpeningStorage();\n                toastr.success('导入完成');\n            };\n            reader.onerror = () => toastr.error('读取文件失败');\n            reader.readAsText(file, 'utf-8');\n        }\n        async function onConfirmClearChronicle() {\n            if (clearChronicleLoading.value)\n                return;\n            clearChronicleLoading.value = true;\n            try {\n                const ok = await clearChronicle();\n                if (ok) {\n                    toastr.success('编年史已清空');\n                }\n                else {\n                    toastr.error('清除失败：当前角色卡未绑定世界书或无法写入世界书');\n                }\n            }\n            catch (e) {\n                console.error('[OpeningForm] clearChronicle:', e);\n                toastr.error('清除失败：' + String(e));\n            }\n            finally {\n                clearChronicleLoading.value = false;\n            }\n        }\n        async function onConfirmClearCache() {\n            if (clearCacheLoading.value)\n                return;\n            clearCacheLoading.value = true;\n            try {\n                await clearOpeningUiCache();\n                toastr.success('浏览器缓存已清理（头像、日记）');\n            }\n            catch (e) {\n                console.error('[OpeningForm] clearCache:', e);\n                toastr.error('清理失败：' + String(e));\n            }\n            finally {\n                clearCacheLoading.value = false;\n            }\n        }\n        /**\n         * 获取所有世界书名称列表\n         * SillyTavern 中完整列表在 /api/settings/get 的 world_names 字段；\n         * /api/worldinfo/get 仅接受 { name } 用于加载单本书，误用会得到 400。\n         */\n        async function fetchAllWorldbookNames() {\n            try {\n                let baseUrl = '';\n                try {\n                    baseUrl = window.parent.location.origin;\n                }\n                catch {\n                    baseUrl = window.location.origin;\n                }\n                const headers = { 'Content-Type': 'application/json' };\n                try {\n                    const h = SillyTavern.getRequestHeaders?.();\n                    if (h && typeof h === 'object') {\n                        Object.assign(headers, h);\n                    }\n                }\n                catch {\n                    /* */\n                }\n                const response = await fetch(`${baseUrl}/api/settings/get`, {\n                    method: 'POST',\n                    headers,\n                    credentials: 'same-origin',\n                    body: JSON.stringify({}),\n                });\n                if (response.ok) {\n                    const data = await response.json();\n                    if (data.world_names && Array.isArray(data.world_names)) {\n                        console.info('[OpeningForm] 通过 /api/settings/get 获取所有世界书:', data.world_names);\n                        return data.world_names;\n                    }\n                }\n                else {\n                    console.warn('[OpeningForm] /api/settings/get 失败:', response.status, response.statusText);\n                }\n            }\n            catch (e) {\n                console.warn('[OpeningForm] 通过 API 获取世界书失败:', e);\n            }\n            // 方法2：尝试从 STScript 获取（仅能获取已绑定的，作为兜底）\n            const allNames = new Set();\n            try {\n                const raw = await triggerSlash('/getglobalbooks');\n                const parsed = JSON.parse(raw || '[]');\n                if (Array.isArray(parsed))\n                    parsed.forEach((n) => allNames.add(n));\n            }\n            catch { /* */ }\n            try {\n                const raw = await triggerSlash('/getcharbook type=all');\n                const parsed = JSON.parse(raw || '[]');\n                if (Array.isArray(parsed))\n                    parsed.forEach((n) => allNames.add(n));\n                else if (typeof parsed === 'string' && parsed)\n                    allNames.add(parsed);\n            }\n            catch { /* */ }\n            console.info('[OpeningForm] STScript 兜底获取的世界书:', Array.from(allNames));\n            return Array.from(allNames);\n        }\n        async function onConfirmClearMsWorldbooks() {\n            if (clearMsWorldbooksLoading.value)\n                return;\n            clearMsWorldbooksLoading.value = true;\n            try {\n                // 1. 获取所有世界书名称\n                const allWorldbooks = await fetchAllWorldbookNames();\n                console.info('[OpeningForm] 所有世界书名称:', allWorldbooks);\n                // 2. 筛选出以 \"ms\" 结尾的世界书\n                const msBooks = allWorldbooks.filter(name => name.trim().endsWith('ms'));\n                console.info('[OpeningForm] ms 结尾的世界书:', msBooks);\n                if (msBooks.length === 0) {\n                    toastr.info('没有找到以 ms 结尾的额外世界书');\n                    return;\n                }\n                toastr.info(`找到 ${msBooks.length} 个额外世界书，开始清理...`);\n                // 3. 逐个删除\n                const deletedBooks = [];\n                for (const bookName of msBooks) {\n                    try {\n                        console.info('[OpeningForm] 尝试删除世界书:', bookName);\n                        const success = await deleteWorldbook(bookName);\n                        if (success) {\n                            deletedBooks.push(bookName);\n                            console.info('[OpeningForm] 已删除:', bookName);\n                        }\n                        else {\n                            console.warn('[OpeningForm] 删除返回失败:', bookName);\n                        }\n                    }\n                    catch (e) {\n                        console.warn('[OpeningForm] 删除异常:', bookName, e);\n                    }\n                }\n                if (deletedBooks.length > 0) {\n                    toastr.success(`已清理 ${deletedBooks.length} 个额外世界书`);\n                }\n                else {\n                    toastr.warning('未能删除任何世界书');\n                }\n            }\n            catch (e) {\n                console.error('[OpeningForm] clearMsWorldbooks:', e);