s\"\nconst __exports__ = /*#__PURE__*/exportComponent(script, [['__scopeId',\"data-v-f467c4b2\"]])\n\nexport default __exports__","/**\n * 游戏内时间系统工具函数\n * 处理游戏内变量时间的格式化、计算等\n * 注意：此时间是游戏世界观内的时间，存储于 MVU 变量中，完全由剧情控制\n * 与现实系统时间无关，不会自动流逝，仅随剧情推进而更新\n */\nimport { useDataStore } from '../store';\n/**\n * 格式化游戏时间为字符串\n */\nexport function formatGameTime(time, template = 'YYYY年MM月DD日 HH:mm') {\n    const { 年, 月, 日, 时, 分 } = time;\n    // 补零函数\n    const pad = (n) => String(n).padStart(2, '0');\n    switch (template) {\n        case 'YYYY年MM月DD日':\n            return `${年}年${pad(月)}月${pad(日)}日`;\n        case 'YYYY-MM-DD':\n            return `${年}-${pad(月)}-${pad(日)}`;\n        case 'MM/DD/YYYY':\n            return `${pad(月)}/${pad(日)}/${年}`;\n        case 'HH:mm':\n            return `${pad(时)}:${pad(分)}`;\n        case 'HH时mm分':\n            return `${pad(时)}时${pad(分)}分`;\n        case 'YYYY年MM月DD日 HH:mm':\n            return `${年}年${pad(月)}月${pad(日)}日 ${pad(时)}:${pad(分)}`;\n        case 'MM月DD日 HH:mm':\n            return `${pad(月)}月${pad(日)}日 ${pad(时)}:${pad(分)}`;\n        case '相对描述':\n            return getTimeRelativeDescription(time);\n        default:\n            return `${年}-${pad(月)}-${pad(日)} ${pad(时)}:${pad(分)}`;\n    }\n}\n/**\n * 获取时间的相对描述（早晨/上午/下午/晚上/深夜）\n */\nexport function getTimeRelativeDescription(time) {\n    const { 时, 分 } = time;\n    const totalMinutes = 时 * 60 + 分;\n    // 5:00 - 8:00: 清晨\n    if (totalMinutes >= 300 && totalMinutes < 480) {\n        return '清晨';\n    }\n    // 8:00 - 11:30: 上午\n    if (totalMinutes >= 480 && totalMinutes < 690) {\n        return '上午';\n    }\n    // 11:30 - 13:30: 中午\n    if (totalMinutes >= 690 && totalMinutes < 810) {\n        return '中午';\n    }\n    // 13:30 - 17:30: 下午\n    if (totalMinutes >= 810 && totalMinutes < 1050) {\n        return '下午';\n    }\n    // 17:30 - 19:30: 傍晚\n    if (totalMinutes >= 1050 && totalMinutes < 1170) {\n        return '傍晚';\n    }\n    // 19:30 - 22:00: 晚上\n    if (totalMinutes >= 1170 && totalMinutes < 1320) {\n        return '晚上';\n    }\n    // 22:00 - 24:00: 深夜\n    if (totalMinutes >= 1320 || totalMinutes < 300) {\n        return '深夜';\n    }\n    return '';\n}\n/**\n * 获取详细时间段描述（带具体时间）\n */\nexport function getDetailedTimeDescription(time) {\n    const period = getTimeRelativeDescription(time);\n    const format = formatGameTime(time, 'HH:mm');\n    return `${period} ${format}`;\n}\n/**\n * 推进游戏时间\n * @param minutes 要推进的分钟数\n */\nexport function advanceGameTime(minutes) {\n    const store = useDataStore();\n    const gameTime = store.data.游戏时间;\n    if (!gameTime) {\n        console.error('[游戏时间] 游戏时间变量未定义');\n        return;\n    }\n    // 推进时间\n    gameTime.分 += Math.round(minutes);\n    console.log(`[游戏时间] 推进了 ${minutes} 分钟，当前时间:`, formatGameTime(gameTime));\n}\n/**\n * 设置游戏时间到指定值\n */\nexport function setGameTime(newTime) {\n    const store = useDataStore();\n    const gameTime = store.data.游戏时间;\n    if (!gameTime) {\n        console.error('[游戏时间] 游戏时间变量未定义');\n        return;\n    }\n    // 更新提供的字段\n    if (newTime.年 !== undefined)\n        gameTime.年 = newTime.年;\n    if (newTime.月 !== undefined)\n        gameTime.月 = newTime.月;\n    if (newTime.日 !== undefined)\n        gameTime.日 = newTime.日;\n    if (newTime.时 !== undefined)\n        gameTime.时 = newTime.时;\n    if (newTime.分 !== undefined)\n        gameTime.分 = newTime.分;\n    console.log(`[游戏时间] 时间已设置:`, formatGameTime(gameTime));\n}\n/**\n * 获取游戏时间的响应式引用（用于Vue组件）\n */\nexport function useGameTime() {\n    const store = useDataStore();\n    return computed({\n        get: () => {\n            const gameTime = store.data.游戏时间;\n            return {\n                年: gameTime?.年 ?? 2026,\n                月: gameTime?.月 ?? 4,\n                日: gameTime?.日 ?? 4,\n                时: gameTime?.时 ?? 12,\n                分: gameTime?.分 ?? 0,\n            };\n        },\n        set: (newTime) => {\n            setGameTime(newTime);\n        },\n    });\n}\n/**\n * 计算两个时间点的差值（以分钟为单位）\n */\nexport function getTimeDifferenceInMinutes(time1, time2) {\n    // 每月按31天计算，与schema保持一致\n    const 每月天数 = 31;\n    const toTotalMinutes = (t) => ((((t.年 * 12) + t.月) * 每月天数) + t.日) * 24 * 60 + t.时 * 60 + t.分;\n    return Math.abs(toTotalMinutes(time1) - toTotalMinutes(time2));\n}\n/**\n * 判断是否是同一天\n */\nexport function isSameDay(time1, time2) {\n    return time1.年 === time2.年 && time1.月 === time2.月 && time1.日 === time2.日;\n}\n/**\n * 判断是否是白天（6:00 - 18:00）\n */\nexport function isDaytime(time) {\n    return time.时 >= 6 && time.时 < 18;\n}\n/**\n * 判断是否是夜晚（18:00 - 6:00）\n */\nexport function isNighttime(time) {\n    return !isDaytime(time);\n}\n/**\n * 获取星期几（基于日期计算，0=周日，1=周一...）\n */\nexport function getDayOfWeek(time) {\n    // 使用基姆拉尔森计算公式（Zeller公式的变体）\n    const { 年, 月, 日 } = time;\n    let y = 年;\n    let m = 月;\n    let d = 日;\n    if (m < 3) {\n        m += 12;\n        y -= 1;\n    }\n    const c = Math.floor(y / 100);\n    const y2 = y % 100;\n    const w = (c / 4 - 2 * c + y2 + y2 / 4 + 13 * (m + 1) / 5 + d - 1) % 7;\n    return Math.floor(w + 7) % 7;\n}\n/**\n * 获取星期几的中文描述\n */\nexport function getDayOfWeekChinese(time) {\n    const days = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];\n    return days[getDayOfWeek(time)];\n}\n/**\n * 获取完整时间显示（用于手机锁屏等场景）\n */\nexport function getFullTimeDisplay(time) {\n    const dateStr = formatGameTime(time, 'YYYY年MM月DD日');\n    const weekStr = getDayOfWeekChinese(time);\n    const timeStr = formatGameTime(time, 'HH:mm');\n    return `${dateStr} ${weekStr} ${timeStr}`;\n}\n","import { defineComponent as _defineComponent } from 'vue';\nimport { createElementVNode as _createElementVNode, toDisplayString as _toDisplayString, openBlock as _openBlock, createElementBlock as _createElementBlock, createCommentVNode as _createCommentVNode, normalizeClass as _normalizeClass } from \"vue\";\nconst _hoisted_1 = { class: \"time-main\" };\nconst _hoisted_2 = { class: \"time-text\" };\nconst _hoisted_3 = {\n    key: 0,\n    cl